{
  "name": "orbital-harmonics",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview",
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "dependencies": {
    "tone": "^14.7.77"
  },
  "devDependencies": {
    "typescript": "^5.4.0",
    "vite": "^5.4.0",
    "vitest": "^2.0.0"
  }
}

import { defineConfig } from 'vite';

export default defineConfig({
  root: '.',
  publicDir: 'public',
  build: {
    outDir: 'dist',
    sourcemap: true,
  },
  server: {
    port: 3000,
    open: true,
  },
});

/* === Global Styles — Orbital Harmonics === */

:root {
  --bg: #0a0a14;
  --panel-bg: rgba(10, 10, 30, 0.85);
  --panel-border: rgba(100, 150, 255, 0.1);
  --text-primary: rgba(255, 255, 255, 0.9);
  --text-secondary: rgba(255, 255, 255, 0.5);
  --accent: #4fc3f7;
  --danger: #ef5350;
  --font: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'SF Mono', 'Fira Code', monospace;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  font-family: var(--font);
  color: var(--text-primary);
  user-select: none;
  -webkit-user-select: none;
}

#canvas {
  display: block;
  width: 100vw;
  height: 100vh;
  cursor: crosshair;
}

/* === Overlay === */
.overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.9);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  transition: opacity 500ms ease-out;
}
.overlay.hidden {
  opacity: 0;
  pointer-events: none;
}
.overlay-content {
  text-align: center;
}
.overlay-content h1 {
  font-size: 48px;
  font-weight: 300;
  letter-spacing: 4px;
  color: var(--accent);
  margin-bottom: 16px;
}
.overlay-content p {
  font-size: 16px;
  color: var(--text-secondary);
}

/* === Panels === */
.panel {
  position: fixed;
  top: 0;
  bottom: 24px;
  background: var(--panel-bg);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  z-index: 10;
  transition: transform 200ms ease-out;
  overflow-y: auto;
  scrollbar-width: thin;
  scrollbar-color: rgba(255,255,255,0.1) transparent;
}
.panel::-webkit-scrollbar { width: 4px; }
.panel::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 2px; }

.sidebar {
  left: 0;
  width: 240px;
  border-radius: 0 8px 8px 0;
  border-right: 1px solid var(--panel-border);
  padding: 12px;
}
.sidebar.collapsed {
  transform: translateX(-240px);
}

.controls {
  right: 0;
  width: 260px;
  border-radius: 8px 0 0 8px;
  border-left: 1px solid var(--panel-border);
  padding: 12px;
}
.controls.collapsed {
  transform: translateX(260px);
}

/* === Panel Sections === */
.panel-section {
  margin-bottom: 16px;
}
.panel-section-title {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

/* === Planet List === */
.planet-list {
  list-style: none;
}
.planet-row {
  display: flex;
  align-items: center;
  height: 32px;
  padding: 0 4px;
  border-left: 3px solid transparent;
  border-radius: 4px;
  cursor: pointer;
  gap: 6px;
  font-size: 13px;
}
.planet-row:hover {
  background: rgba(255, 255, 255, 0.05);
}
.planet-row.selected {
  border-left-color: var(--accent);
  background: rgba(255, 255, 255, 0.08);
}
.planet-row.muted {
  opacity: 0.4;
}
.planet-color-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}
.planet-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.planet-synth-label {
  font-size: 10px;
  color: var(--text-secondary);
  font-family: var(--font-mono);
  width: 28px;
  text-align: center;
}
.planet-btn {
  background: none;
  border: none;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 14px;
  padding: 2px;
  border-radius: 3px;
  line-height: 1;
}
.planet-btn:hover {
  background: rgba(255, 255, 255, 0.1);
  color: var(--text-primary);
}
.planet-btn.active {
  color: var(--accent);
}
.planet-btn.delete:hover {
  color: var(--danger);
}

.empty-state {
  color: var(--text-secondary);
  font-size: 12px;
  text-align: center;
  padding: 20px 8px;
  line-height: 1.5;
}

/* === Controls === */
.control-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 28px;
  margin-bottom: 4px;
}
.control-label {
  font-size: 11px;
  color: var(--text-secondary);
}
.control-value {
  font-size: 11px;
  font-family: var(--font-mono);
  color: var(--text-primary);
  min-width: 36px;
  text-align: right;
}
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.15);
  border-radius: 2px;
  outline: none;
  margin: 4px 0;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 14px;
  height: 14px;
  background: var(--accent);
  border-radius: 50%;
  cursor: pointer;
}
input[type="range"]::-moz-range-thumb {
  width: 14px;
  height: 14px;
  background: var(--accent);
  border-radius: 50%;
  border: none;
  cursor: pointer;
}
select {
  background: rgba(255, 255, 255, 0.08);
  color: var(--text-primary);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 4px;
  padding: 3px 6px;
  font-size: 11px;
  font-family: var(--font-mono);
  cursor: pointer;
  outline: none;
}
select:hover {
  border-color: rgba(255, 255, 255, 0.3);
}
.toggle-switch {
  position: relative;
  width: 36px;
  height: 20px;
  background: rgba(255, 255, 255, 0.15);
  border-radius: 10px;
  cursor: pointer;
  transition: background 200ms;
}
.toggle-switch.on {
  background: var(--accent);
}
.toggle-switch::after {
  content: '';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  background: white;
  border-radius: 50%;
  transition: transform 200ms;
}
.toggle-switch.on::after {
  transform: translateX(16px);
}

.btn {
  background: rgba(255, 255, 255, 0.08);
  color: var(--text-primary);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 4px;
  padding: 4px 10px;
  font-size: 11px;
  cursor: pointer;
  font-family: var(--font);
}
.btn:hover {
  background: rgba(255, 255, 255, 0.15);
}
.btn-row {
  display: flex;
  gap: 6px;
  margin-top: 4px;
}

/* === Status Bar === */
.status-bar {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 24px;
  background: rgba(10, 10, 20, 0.8);
  backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 16px;
  font-size: 11px;
  font-family: var(--font-mono);
  color: var(--text-secondary);
  z-index: 10;
  transition: opacity 300ms;
}
.status-bar.hidden {
  opacity: 0;
  pointer-events: none;
}
.status-left, .status-center, .status-right {
  min-width: 120px;
}
.status-center {
  text-align: center;
}
.status-right {
  text-align: right;
}

/* === Planet Editor === */
.planet-editor {
  border-top: 1px solid var(--panel-border);
  margin-top: 8px;
  padding-top: 8px;
}

/* === Shortcuts Overlay === */
.shortcuts-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1001;
}
.shortcuts-content {
  background: var(--panel-bg);
  backdrop-filter: blur(12px);
  border-radius: 12px;
  padding: 24px 32px;
  max-width: 400px;
}
.shortcuts-content h2 {
  font-size: 16px;
  margin-bottom: 12px;
  color: var(--accent);
}
.shortcut-row {
  display: flex;
  justify-content: space-between;
  padding: 4px 0;
  font-size: 12px;
}
.shortcut-key {
  font-family: var(--font-mono);
  color: var(--accent);
  min-width: 80px;
}
.shortcut-desc {
  color: var(--text-secondary);
}

/* === Toggle tabs === */
.panel-toggle {
  position: fixed;
  z-index: 11;
  background: var(--panel-bg);
  backdrop-filter: blur(8px);
  border: 1px solid var(--panel-border);
  color: var(--text-secondary);
  width: 24px;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 12px;
  transition: color 150ms, background 150ms;
}
.panel-toggle:hover {
  color: var(--text-primary);
  background: rgba(10, 10, 30, 0.95);
}
.sidebar-toggle {
  top: 50%;
  transform: translateY(-50%);
  left: 240px;
  border-radius: 0 6px 6px 0;
  border-left: none;
}
.sidebar-toggle.collapsed {
  left: 0;
}
.controls-toggle {
  top: 50%;
  transform: translateY(-50%);
  right: 260px;
  border-radius: 6px 0 0 6px;
  border-right: none;
}
.controls-toggle.collapsed {
  right: 0;
}

/**
 * Vector2 operations and math utilities for the simulation engine.
 * All operations return new objects — no mutation.
 */

export interface Vector2 {
  x: number;
  y: number;
}

export function vec2(x: number, y: number): Vector2 {
  return { x, y };
}

export function add(a: Vector2, b: Vector2): Vector2 {
  return { x: a.x + b.x, y: a.y + b.y };
}

export function sub(a: Vector2, b: Vector2): Vector2 {
  return { x: a.x - b.x, y: a.y - b.y };
}

export function scale(v: Vector2, s: number): Vector2 {
  return { x: v.x * s, y: v.y * s };
}

export function magnitude(v: Vector2): number {
  return Math.sqrt(v.x * v.x + v.y * v.y);
}

export function magnitudeSq(v: Vector2): number {
  return v.x * v.x + v.y * v.y;
}

export function normalize(v: Vector2): Vector2 {
  const mag = magnitude(v);
  if (mag === 0) return { x: 0, y: 0 };
  return { x: v.x / mag, y: v.y / mag };
}

export function dot(a: Vector2, b: Vector2): number {
  return a.x * b.x + a.y * b.y;
}

export function distance(a: Vector2, b: Vector2): number {
  return magnitude(sub(a, b));
}

export function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function mapRange(
  value: number,
  inMin: number,
  inMax: number,
  outMin: number,
  outMax: number,
): number {
  const t = clamp((value - inMin) / (inMax - inMin), 0, 1);
  return outMin + t * (outMax - outMin);
}

/**
 * Color utilities and planet color palette.
 * Palette per spec §04.6.3 — vibrant, distinguishable colors that cycle as planets spawn.
 */

/** Curated planet palette from spec */
export const PLANET_PALETTE = [
  '#4fc3f7', '#81c784', '#fff176', '#ff8a65', '#ce93d8',
  '#f06292', '#4dd0e1', '#aed581', '#ffb74d', '#ba68c8',
] as const;

let paletteIndex = 0;

/** Get next color from the palette, cycling when exhausted */
export function nextPaletteColor(): string {
  const color = PLANET_PALETTE[paletteIndex % PLANET_PALETTE.length];
  paletteIndex++;
  return color;
}

/** Reset the palette index (e.g., on full reset) */
export function resetPaletteIndex(): void {
  paletteIndex = 0;
}

/** Parse a hex color to RGB components */
export function hexToRgb(hex: string): { r: number; g: number; b: number } {
  const h = hex.replace('#', '');
  return {
    r: parseInt(h.substring(0, 2), 16),
    g: parseInt(h.substring(2, 4), 16),
    b: parseInt(h.substring(4, 6), 16),
  };
}

/** Create an rgba() string from hex color and alpha */
export function hexToRgba(hex: string, alpha: number): string {
  const { r, g, b } = hexToRgb(hex);
  return `rgba(${r},${g},${b},${alpha})`;
}

/**
 * Unique ID generator for celestial bodies.
 * Simple counter-based IDs are sufficient — no need for UUIDs.
 */

let counter = 0;

/** Generate a unique body ID */
export function generateId(): string {
  return `body-${++counter}`;
}

/** Reset the counter (e.g., on full reset) */
export function resetIdCounter(): void {
  counter = 0;
}

/**
 * Core types for the physics simulation engine.
 * Re-exports Vector2 from lib/math for convenience.
 */

import type { Vector2 } from '../lib/math.js';

export type { Vector2 };

export interface Body {
  id: string;
  mass: number;
  position: Vector2;
  velocity: Vector2;
  acceleration: Vector2;
  prevPosition: Vector2;
  radius: number;
  isAnchor: boolean;
  color: string;
  /** Timestamp when planet was flagged as escaped (0 = not escaped) */
  escapedAt: number;
  /** User-assigned name */
  name: string;
  /** Mute state (visual dimming) */
  muted: boolean;
  /** Solo state */
  soloed: boolean;
}

export interface SimulationState {
  bodies: Body[];
  sun: Body;
  running: boolean;
  G: number;
  softening: number;
  nBodyEnabled: boolean;
  simSpeed: number;
}

/**
 * Default constants for the simulation engine.
 * Values per spec §02.9 and §06.6.
 */

/** Gravitational constant (tunable as "Gravity Strength") */
export const G = 1.0;

/** Softening parameter to prevent singularities at near-zero distance */
export const SOFTENING = 5.0;

/** Fixed time step matching RAF frame rate */
export const DT = 1 / 60;

/** Default sun mass */
export const SUN_MASS = 10000;

/** Converts pixel-drag-distance into simulation velocity units */
export const VELOCITY_MULTIPLIER = 0.05;

/** Minimum planet mass */
export const MIN_MASS = 1;

/** Maximum planet mass */
export const MAX_MASS = 50;

/** Minimum visual radius in pixels */
export const MIN_RADIUS = 4;

/** Maximum visual radius in pixels */
export const MAX_RADIUS = 20;

/** Distance threshold multiplier for escape detection (× canvas diagonal) */
export const ESCAPE_DISTANCE_FACTOR = 2;

/** Grace period in ms before an escaped planet is removed */
export const ESCAPE_GRACE_PERIOD = 5000;

/** Compute visual radius from mass: mass^(1/3) * 2, clamped to [4, 20] */
export function massToRadius(mass: number): number {
  return Math.max(MIN_RADIUS, Math.min(MAX_RADIUS, Math.pow(mass, 1 / 3) * 2));
}

/**
 * Gravitational force computation.
 * Implements F = G*m1*m2 / (r² + ε²) with Newton's 3rd law optimization.
 */

import type { Body } from './types.js';
import { sub, magnitudeSq } from '../lib/math.js';

/**
 * Compute the gravitational force vector from body `a` toward body `b`.
 * Returns the force magnitude times the direction unit vector from a→b.
 */
export function gravitationalForce(
  a: Body,
  b: Body,
  G: number,
  softening: number,
): { fx: number; fy: number } {
  const dx = b.position.x - a.position.x;
  const dy = b.position.y - a.position.y;
  const distSq = dx * dx + dy * dy + softening * softening;
  const dist = Math.sqrt(distSq);
  const forceMag = (G * a.mass * b.mass) / distSq;
  return {
    fx: forceMag * (dx / dist),
    fy: forceMag * (dy / dist),
  };
}

/**
 * Compute all pairwise gravitational forces and update accelerations.
 * Uses Newton's 3rd law: compute each pair once, apply equal-and-opposite.
 * When nBodyEnabled is false, only computes forces between each planet and the sun.
 */
export function computeForces(
  bodies: Body[],
  sun: Body,
  G: number,
  softening: number,
  nBodyEnabled: boolean,
): void {
  // Reset accelerations
  for (const body of bodies) {
    body.acceleration.x = 0;
    body.acceleration.y = 0;
  }

  // All planets are attracted to the sun (sun is immovable, so skip applying force to sun)
  for (const body of bodies) {
    if (body.isAnchor) continue;
    const { fx, fy } = gravitationalForce(body, sun, G, softening);
    body.acceleration.x += fx / body.mass;
    body.acceleration.y += fy / body.mass;
  }

  // N-body: pairwise planet interactions
  if (nBodyEnabled) {
    const planets = bodies.filter((b) => !b.isAnchor);
    for (let i = 0; i < planets.length; i++) {
      for (let j = i + 1; j < planets.length; j++) {
        const { fx, fy } = gravitationalForce(planets[i], planets[j], G, softening);
        planets[i].acceleration.x += fx / planets[i].mass;
        planets[i].acceleration.y += fy / planets[i].mass;
        planets[j].acceleration.x -= fx / planets[j].mass;
        planets[j].acceleration.y -= fy / planets[j].mass;
      }
    }
  }
}

/**
 * Velocity Verlet integration step.
 * Symplectic integrator that conserves energy over long simulations.
 *
 * Algorithm:
 *   1. x(t+dt) = x(t) + v(t)*dt + 0.5*a(t)*dt²
 *   2. Compute a(t+dt) from new positions
 *   3. v(t+dt) = v(t) + 0.5*(a(t) + a(t+dt))*dt
 */

import type { Body } from './types.js';

/**
 * Save current accelerations and update positions.
 * Step 1 of Velocity Verlet — must be followed by force recomputation and then velocityUpdate.
 */
export function positionUpdate(bodies: Body[], dt: number): void {
  for (const body of bodies) {
    if (body.isAnchor) continue; // sun is immovable
    // Save prev position for axis-crossing detection
    body.prevPosition.x = body.position.x;
    body.prevPosition.y = body.position.y;

    // Store current acceleration for velocity update step
    body.acceleration.x; // will be used after recomputation

    // Position update: x(t+dt) = x(t) + v(t)*dt + 0.5*a(t)*dt²
    body.position.x += body.velocity.x * dt + 0.5 * body.acceleration.x * dt * dt;
    body.position.y += body.velocity.y * dt + 0.5 * body.acceleration.y * dt * dt;
  }
}

/**
 * Update velocities after forces have been recomputed at new positions.
 * Step 3 of Velocity Verlet.
 * `oldAccelerations` holds the accelerations from before the position update.
 */
export function velocityUpdate(
  bodies: Body[],
  oldAccelerations: { x: number; y: number }[],
  dt: number,
): void {
  let i = 0;
  for (const body of bodies) {
    if (body.isAnchor) {
      i++;
      continue;
    }
    // v(t+dt) = v(t) + 0.5*(a_old(t) + a_new(t+dt)) * dt
    body.velocity.x += 0.5 * (oldAccelerations[i].x + body.acceleration.x) * dt;
    body.velocity.y += 0.5 * (oldAccelerations[i].y + body.acceleration.y) * dt;
    i++;
  }
}

/**
 * Save current accelerations for later use in velocity update.
 */
export function saveAccelerations(bodies: Body[]): { x: number; y: number }[] {
  return bodies.map((b) => ({ x: b.acceleration.x, y: b.acceleration.y }));
}

/**
 * Main Simulation class.
 * Manages bodies, runs the Velocity Verlet integration step, and detects escaped planets.
 */

import type { Body, SimulationState } from './types.js';
import type { Vector2 } from '../lib/math.js';
import { vec2, distance } from '../lib/math.js';
import { generateId } from '../lib/id.js';
import { nextPaletteColor } from '../lib/colors.js';
import { computeForces } from './forces.js';
import { positionUpdate, velocityUpdate, saveAccelerations } from './integrator.js';
import {
  G as DEFAULT_G,
  SOFTENING,
  DT,
  SUN_MASS,
  VELOCITY_MULTIPLIER,
  ESCAPE_DISTANCE_FACTOR,
  ESCAPE_GRACE_PERIOD,
  massToRadius,
} from './constants.js';

let planetCounter = 0;

export class Simulation {
  bodies: Body[] = [];
  sun: Body;
  running = true;
  G = DEFAULT_G;
  softening = SOFTENING;
  nBodyEnabled = true;
  simSpeed = 1.0;
  dt = DT;

  /** Callbacks */
  onBodyRemoved?: (id: string) => void;
  onBodyAdded?: (body: Body) => void;

  private canvasDiagonal = 2000; // updated on resize

  constructor(canvasWidth: number, canvasHeight: number) {
    this.canvasDiagonal = Math.sqrt(canvasWidth * canvasWidth + canvasHeight * canvasHeight);
    this.sun = this.createSun(canvasWidth / 2, canvasHeight / 2);
    this.bodies.push(this.sun);
  }

  /** Update canvas dimensions (call on resize) */
  updateCanvasSize(width: number, height: number): void {
    this.canvasDiagonal = Math.sqrt(width * width + height * height);
    this.sun.position.x = width / 2;
    this.sun.position.y = height / 2;
  }

  private createSun(x: number, y: number): Body {
    return {
      id: 'sun',
      mass: SUN_MASS,
      position: vec2(x, y),
      velocity: vec2(0, 0),
      acceleration: vec2(0, 0),
      prevPosition: vec2(x, y),
      radius: 25,
      isAnchor: true,
      color: '#ffd54f',
      escapedAt: 0,
      name: 'Sun',
      muted: false,
      soloed: false,
    };
  }

  /** Add a new planet with the given position and initial velocity */
  addPlanet(
    position: Vector2,
    velocity: Vector2,
    mass: number,
  ): Body {
    planetCounter++;
    const body: Body = {
      id: generateId(),
      mass,
      position: { ...position },
      velocity: { ...velocity },
      acceleration: vec2(0, 0),
      prevPosition: { ...position },
      radius: massToRadius(mass),
      isAnchor: false,
      color: nextPaletteColor(),
      escapedAt: 0,
      name: `Planet ${planetCounter}`,
      muted: false,
      soloed: false,
    };
    this.bodies.push(body);
    this.onBodyAdded?.(body);
    return body;
  }

  /** Remove a body by ID */
  removeBody(id: string): void {
    const idx = this.bodies.findIndex((b) => b.id === id);
    if (idx !== -1 && !this.bodies[idx].isAnchor) {
      this.bodies.splice(idx, 1);
      this.onBodyRemoved?.(id);
    }
  }

  /** Remove all planets (keep the sun) */
  reset(): void {
    const removed = this.bodies.filter((b) => !b.isAnchor);
    this.bodies = [this.sun];
    for (const b of removed) {
      this.onBodyRemoved?.(b.id);
    }
    planetCounter = 0;
  }

  /** Execute one simulation step using Velocity Verlet */
  step(): void {
    if (!this.running) return;

    const dt = this.dt * this.simSpeed;

    // 1. Save old accelerations
    const oldAcc = saveAccelerations(this.bodies);

    // 2. Position update (step 1 of Velocity Verlet)
    positionUpdate(this.bodies, dt);

    // 3. Recompute forces at new positions
    computeForces(this.bodies, this.sun, this.G, this.softening, this.nBodyEnabled);

    // 4. Velocity update (step 3 of Velocity Verlet)
    velocityUpdate(this.bodies, oldAcc, dt);

    // 5. Detect escaped planets
    this.detectEscaped();
  }

  private detectEscaped(): void {
    const escapeDist = ESCAPE_DISTANCE_FACTOR * this.canvasDiagonal / 2;
    const now = performance.now();

    for (const body of this.bodies) {
      if (body.isAnchor) continue;

      const dist = distance(body.position, this.sun.position);
      if (dist > escapeDist) {
        if (body.escapedAt === 0) {
          body.escapedAt = now;
        } else if (now - body.escapedAt > ESCAPE_GRACE_PERIOD) {
          this.removeBody(body.id);
        }
      } else {
        body.escapedAt = 0;
      }
    }
  }

  /** Get all planet bodies (excluding the sun) */
  get planets(): Body[] {
    return this.bodies.filter((b) => !b.isAnchor);
  }

  /** Get a snapshot of the simulation state */
  get state(): SimulationState {
    return {
      bodies: [...this.bodies],
      sun: this.sun,
      running: this.running,
      G: this.G,
      softening: this.softening,
      nBodyEnabled: this.nBodyEnabled,
      simSpeed: this.simSpeed,
    };
  }
}

