/**
 * Central reactive state store with subscribe/notify pattern.
 * Lightweight custom observable — no framework dependency.
 */

import type { AppState, SettingsState, PlanetState, TriggerLineState } from './types.js';
import type { ScaleMode, SynthType } from '../audio/types.js';

type Listener = () => void;

const defaultSettings: SettingsState = {
  gravity: 1.0,
  nBodyEnabled: true,
  trailFadeRate: 0.03,
  simSpeed: 1.0,
  root: 'C',
  mode: 'lydian',
  octaveMin: 3,
  octaveMax: 5,
  defaultSynth: 'fm',
  reverbMix: 0.3,
  delayMix: 0.2,
  masterVolume: 0.75,
};

const state: AppState = {
  settings: { ...defaultSettings },
  planets: new Map(),
  triggerLines: [
    { id: 'line-0', angle: 0 },           // X axis
    { id: 'line-1', angle: Math.PI / 2 },  // Y axis
  ],
  selectedPlanetId: null,
  selectedTriggerLineId: null,
};

const listeners = new Set<Listener>();

/** Subscribe to state changes. Returns unsubscribe function. */
export function subscribe(listener: Listener): () => void {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

/** Notify all subscribers of a state change */
export function notify(): void {
  for (const listener of listeners) {
    listener();
  }
}

/** Get a read-only reference to the current state */
export function getState(): Readonly<AppState> {
  return state;
}

// === Settings mutations ===

export function updateSettings(patch: Partial<SettingsState>): void {
  Object.assign(state.settings, patch);
  notify();
}

// === Planet mutations ===

export function addPlanet(planet: PlanetState): void {
  state.planets.set(planet.id, planet);
  notify();
}

export function removePlanet(id: string): void {
  state.planets.delete(id);
  if (state.selectedPlanetId === id) {
    state.selectedPlanetId = null;
  }
  notify();
}

export function updatePlanet(id: string, patch: Partial<PlanetState>): void {
  const planet = state.planets.get(id);
  if (planet) {
    Object.assign(planet, patch);
    notify();
  }
}

// === Selection ===

export function selectPlanet(id: string | null): void {
  state.selectedPlanetId = id;
  notify();
}

export function selectTriggerLine(id: string | null): void {
  state.selectedTriggerLineId = id;
  notify();
}

// === Trigger lines ===

export function addTriggerLine(): string | null {
  if (state.triggerLines.length >= 6) return null;
  const id = `line-${state.triggerLines.length}`;
  // Add at a evenly spaced angle
  const angle = (state.triggerLines.length * Math.PI) / state.triggerLines.length;
  state.triggerLines.push({ id, angle });
  notify();
  return id;
}

export function updateTriggerLine(id: string, angle: number): void {
  const line = state.triggerLines.find((l) => l.id === id);
  if (line) {
    line.angle = angle;
    notify();
  }
}

export function resetTriggerLines(): void {
  state.triggerLines = [
    { id: 'line-0', angle: 0 },
    { id: 'line-1', angle: Math.PI / 2 },
  ];
  state.selectedTriggerLineId = null;
  notify();
}

export function resetAll(): void {
  state.planets.clear();
  state.selectedPlanetId = null;
  state.selectedTriggerLineId = null;
  state.settings = { ...defaultSettings };
  state.triggerLines = [
    { id: 'line-0', angle: 0 },
    { id: 'line-1', angle: Math.PI / 2 },
  ];
  notify();
}

/**
 * Audio engine type definitions.
 */

export type SynthType = 'sine' | 'triangle' | 'sawtooth' | 'square' | 'fm' | 'marimba' | 'bell' | 'pluck';

export type ScaleMode =
  | 'ionian' | 'dorian' | 'phrygian' | 'lydian'
  | 'mixolydian' | 'aeolian' | 'locrian';

export interface ScaleConfig {
  root: string;
  mode: ScaleMode;
  octaveRange: [number, number];
}

export interface TriggerEvent {
  planetId: string;
  axis: number;           // trigger line index
  crossingDirection: 1 | -1;
  distance: number;
  velocity: number;
  angle: number;
}

export const SYNTH_LABELS: Record<SynthType, string> = {
  sine: 'SIN',
  triangle: 'TRI',
  sawtooth: 'SAW',
  square: 'SQR',
  fm: 'FM',
  marimba: 'MAR',
  bell: 'BEL',
  pluck: 'PLK',
};

/**
 * Musical scale definitions and note array generation.
 * All 7 standard modes per spec §06.3.3.
 */

import type { ScaleMode } from './types.js';

/** Semitone intervals from root for each mode */
export const SCALES: Record<ScaleMode, number[]> = {
  ionian:     [0, 2, 4, 5, 7, 9, 11],
  dorian:     [0, 2, 3, 5, 7, 9, 10],
  phrygian:   [0, 1, 3, 5, 7, 8, 10],
  lydian:     [0, 2, 4, 6, 7, 9, 11],
  mixolydian: [0, 2, 4, 5, 7, 9, 10],
  aeolian:    [0, 2, 3, 5, 7, 8, 10],
  locrian:    [0, 1, 3, 5, 6, 8, 10],
};

/** Root note name → semitone offset from C */
const ROOT_SEMITONES: Record<string, number> = {
  'C': 0, 'C#': 1, 'Db': 1,
  'D': 2, 'D#': 3, 'Eb': 3,
  'E': 4,
  'F': 5, 'F#': 6, 'Gb': 6,
  'G': 7, 'G#': 8, 'Ab': 8,
  'A': 9, 'A#': 10, 'Bb': 10,
  'B': 11,
};

/** Convert a root note name to its semitone offset from C */
export function noteToMidi(root: string): number {
  return ROOT_SEMITONES[root] ?? 0;
}

/**
 * Generate the full array of MIDI note numbers for a given root, mode, and octave range.
 * Notes are sorted ascending.
 */
export function generateNoteArray(
  root: string,
  mode: ScaleMode,
  octaveMin: number,
  octaveMax: number,
): number[] {
  const rootMidi = noteToMidi(root);
  const intervals = SCALES[mode];
  const notes: number[] = [];

  for (let octave = octaveMin; octave <= octaveMax; octave++) {
    for (const interval of intervals) {
      notes.push(rootMidi + interval + octave * 12);
    }
  }

  return notes.sort((a, b) => a - b);
}

/** MIDI note number → frequency in Hz (A4 = 440Hz) */
export function midiToFrequency(midi: number): number {
  return 440 * Math.pow(2, (midi - 69) / 12);
}

/**
 * Distance → pitch quantizer.
 * Maps a planet's radial distance from the sun to a quantized MIDI note.
 * Close = high pitch, far = low pitch (per spec §06.3).
 */

import { clamp } from '../lib/math.js';

const MIN_DISTANCE = 50;
const MAX_DISTANCE = 400;

/**
 * Map a radial distance to a MIDI note number from the given scale notes.
 * Close to sun = high pitch, far from sun = low pitch.
 */
export function distanceToNote(
  distance: number,
  scaleNotes: number[],
  minDistance: number = MIN_DISTANCE,
  maxDistance: number = MAX_DISTANCE,
): number {
  if (scaleNotes.length === 0) return 60; // middle C fallback

  // Normalize to [0, 1]
  const normalized = clamp(
    (distance - minDistance) / (maxDistance - minDistance),
    0,
    1,
  );

  // Reverse: close = high pitch (high index), far = low pitch (low index)
  const index = Math.floor((1 - normalized) * (scaleNotes.length - 1));
  return scaleNotes[clamp(index, 0, scaleNotes.length - 1)];
}

/**
 * Trigger line crossing detection.
 * Detects when a planet crosses a trigger line using signed distance sign change.
 * Includes debounce per planet per line.
 */

import type { Body } from '../simulation/types.js';
import type { TriggerEvent } from './types.js';
import type { TriggerLineState } from '../state/types.js';

const DEBOUNCE_MS = 100;

interface DebounceKey {
  planetId: string;
  lineId: string;
}

export class TriggerDetector {
  private lastTriggerTime = new Map<string, number>();
  private triggerLines: TriggerLineState[] = [];

  constructor(lines: TriggerLineState[]) {
    this.triggerLines = lines;
  }

  /** Update trigger lines (call when state changes) */
  setLines(lines: TriggerLineState[]): void {
    this.triggerLines = lines;
  }

  /**
   * Check all planets against all trigger lines for crossings.
   * Returns an array of TriggerEvents for any detected crossings.
   */
  detect(planets: Body[], sunX: number, sunY: number): TriggerEvent[] {
    const events: TriggerEvent[] = [];
    const now = performance.now();

    for (const planet of planets) {
      if (planet.isAnchor) continue;

      for (let li = 0; li < this.triggerLines.length; li++) {
        const line = this.triggerLines[li];
        const angle = line.angle;

        // Signed distance from line: positive on one side, negative on the other
        // Line goes through sun at (sunX, sunY) at the given angle
        // Normal to the line is (sin(angle), -cos(angle))
        const nx = Math.sin(angle);
        const ny = -Math.cos(angle);

        const prevDx = planet.prevPosition.x - sunX;
        const prevDy = planet.prevPosition.y - sunY;
        const currDx = planet.position.x - sunX;
        const currDy = planet.position.y - sunY;

        const prevSigned = prevDx * nx + prevDy * ny;
        const currSigned = currDx * nx + currDy * ny;

        // Crossing detected if signs differ
        if (prevSigned * currSigned < 0) {
          // Debounce check
          const debounceKey = `${planet.id}:${line.id}`;
          const lastTime = this.lastTriggerTime.get(debounceKey) ?? 0;
          if (now - lastTime < DEBOUNCE_MS) continue;

          this.lastTriggerTime.set(debounceKey, now);

          // Interpolate crossing position
          const t = Math.abs(prevSigned) / (Math.abs(prevSigned) + Math.abs(currSigned));
          const crossX = prevDx + t * (currDx - prevDx);
          const crossY = prevDy + t * (currDy - prevDy);

          const dist = Math.sqrt(crossX * crossX + crossY * crossY);
          const vel = Math.sqrt(
            planet.velocity.x * planet.velocity.x +
            planet.velocity.y * planet.velocity.y,
          );
          const angle2 = Math.atan2(crossY, crossX);
          const direction = currSigned > 0 ? 1 : -1;

          events.push({
            planetId: planet.id,
            axis: li,
            crossingDirection: direction as 1 | -1,
            distance: dist,
            velocity: vel,
            angle: angle2,
          });
        }
      }
    }

    return events;
  }
}

/**
 * Audio effects chain: Reverb → Delay → Limiter → Master Gain.
 * Uses Tone.js nodes for all processing.
 */

import * as Tone from 'tone';

export class EffectsChain {
  reverb: Tone.Reverb;
  delay: Tone.FeedbackDelay;
  limiter: Tone.Limiter;
  masterGain: Tone.Gain;

  constructor() {
    this.reverb = new Tone.Reverb({ decay: 2.5, wet: 0.3, preDelay: 0.01 });
    this.delay = new Tone.FeedbackDelay({ delayTime: 0.375, feedback: 0.3, wet: 0.2 });
    this.limiter = new Tone.Limiter(-1);
    this.masterGain = new Tone.Gain(0.75);

    // Chain: reverb → delay → limiter → master → destination
    this.reverb.connect(this.delay);
    this.delay.connect(this.limiter);
    this.limiter.connect(this.masterGain);
    this.masterGain.toDestination();
  }

  /** Get the input node that voices should connect to */
  get input(): Tone.ToneAudioNode {
    return this.reverb;
  }

  setReverbMix(wet: number): void {
    this.reverb.wet.value = wet;
  }

  setDelayMix(wet: number): void {
    this.delay.wet.value = wet;
  }

  setMasterVolume(volume: number): void {
    this.masterGain.gain.value = volume;
  }

  dispose(): void {
    this.reverb.dispose();
    this.delay.dispose();
    this.limiter.dispose();
    this.masterGain.dispose();
  }
}

/**
 * Per-planet synth voice management.
 * Creates, updates, and disposes synth voices with the correct signal chain:
 *   Synth → Gain → Pan → Effects Bus
 */

import * as Tone from 'tone';
import type { SynthType } from './types.js';
import { EffectsChain } from './effects.js';

export interface PlanetVoice {
  planetId: string;
  synth: Tone.ToneAudioNode;
  gainNode: Tone.Gain;
  panNode: Tone.Panner;
  synthType: SynthType;
}

/**
 * Create a synth instance based on the given type.
 * Returns a ToneAudioNode that can be triggered with triggerAttackRelease.
 */
function createSynth(type: SynthType): Tone.ToneAudioNode {
  switch (type) {
    case 'sine':
      return new Tone.Synth({
        oscillator: { type: 'sine' },
        envelope: { attack: 0.01, decay: 0.3, sustain: 0.2, release: 0.5 },
      });
    case 'triangle':
      return new Tone.Synth({
        oscillator: { type: 'triangle' },
        envelope: { attack: 0.01, decay: 0.3, sustain: 0.2, release: 0.5 },
      });
    case 'sawtooth': {
      const synth = new Tone.Synth({
        oscillator: { type: 'sawtooth' },
        envelope: { attack: 0.005, decay: 0.2, sustain: 0.1, release: 0.3 },
      });
      const filter = new Tone.Filter(2000, 'lowpass');
      synth.connect(filter);
      return filter;
    }
    case 'square': {
      const synth = new Tone.Synth({
        oscillator: { type: 'square' },
        envelope: { attack: 0.005, decay: 0.2, sustain: 0.1, release: 0.3 },
      });
      const filter = new Tone.Filter(2000, 'lowpass');
      synth.connect(filter);
      return filter;
    }
    case 'fm':
      return new Tone.FMSynth({
        harmonicity: 1,
        modulationIndex: 10,
        envelope: { attack: 0.01, decay: 0.5, sustain: 0.3, release: 0.8 },
      });
    case 'marimba':
      return new Tone.PluckSynth({
        attackNoise: 2,
        dampening: 4000,
        resonance: 0.9,
      });
    case 'bell':
      return new Tone.FMSynth({
        harmonicity: 3.5,
        modulationIndex: 14,
        envelope: { attack: 0.01, decay: 1.0, sustain: 0.1, release: 1.5 },
      });
    case 'pluck':
      return new Tone.PluckSynth({
        attackNoise: 1,
        dampening: 3000,
        resonance: 0.95,
      });
  }
}

/**
 * Create a full voice chain for a planet: Synth → Gain → Pan → Effects.
 */
export function createVoice(
  planetId: string,
  synthType: SynthType,
  effects: EffectsChain,
): PlanetVoice {
  const synth = createSynth(synthType);
  const gainNode = new Tone.Gain(0.75);
  const panNode = new Tone.Panner(0);

  synth.connect(gainNode);
  gainNode.connect(panNode);
  panNode.connect(effects.input);

  return { planetId, synth, gainNode, panNode, synthType };
}

/**
 * Trigger a note on a voice.
 */
export function triggerNote(
  voice: PlanetVoice,
  frequency: number,
  duration: string,
  velocity: number,
  normalizedVelocity: number,
): void {
  const synth = voice.synth;

  // Apply velocity-to-timbre modulation based on synth type
  if (synth instanceof Tone.FMSynth) {
    // FM: velocity → modulation index (faster = more metallic)
    const modIndex = 1 + normalizedVelocity * 19; // range 1-20
    synth.modulationIndex.value = modIndex;
  }

  // For filtered synths (saw/square), modulate filter
  if (voice.synthType === 'sawtooth' || voice.synthType === 'square') {
    // The synth node is actually a Filter in this case
    const filter = synth as unknown as Tone.Filter;
    if (filter.frequency) {
      const cutoff = 200 + normalizedVelocity * 7800; // 200-8000Hz
      filter.frequency.value = cutoff;
    }
  }

  // Set volume based on velocity
  voice.gainNode.gain.value = velocity;

  // Trigger the note
  if (synth instanceof Tone.PluckSynth) {
    synth.triggerAttack(frequency);
  } else if (synth instanceof Tone.FMSynth) {
    synth.triggerAttackRelease(frequency, duration);
  } else if (synth instanceof Tone.Synth) {
    synth.triggerAttackRelease(frequency, duration);
  } else {
    // Filter node for saw/square — need to reach the synth behind it
    const filter = synth;
    // For filtered synths, we stored them differently
    // The synth is connected to the filter, so we need the synth reference
    // Actually, in our createSynth, we return the filter node as the "synth"
    // The real synth is connected to it. We need to handle this differently.
    // For now, let's just try to trigger on the returned node
    try {
      (synth as Tone.Synth).triggerAttackRelease?.(frequency, duration);
    } catch {
      // Ignore if not triggerable
    }
  }
}

/**
 * Dispose a voice and all its audio nodes.
 */
export function disposeVoice(voice: PlanetVoice): void {
  try {
    if (voice.synth instanceof Tone.PluckSynth) {
      voice.synth.dispose();
    } else if (voice.synth instanceof Tone.FMSynth) {
      voice.synth.dispose();
    } else if (voice.synth instanceof Tone.Synth) {
      voice.synth.dispose();
    } else if (voice.synth instanceof Tone.Filter) {
      voice.synth.dispose();
    }
  } catch {
    // Best effort disposal
  }
  voice.gainNode.dispose();
  voice.panNode.dispose();
}

/**
 * Update a voice's synth type by disposing the old synth and creating a new one.
 * Reconnects to the existing gain/pan chain.
 */
export function updateVoiceSynth(
  voice: PlanetVoice,
  newType: SynthType,
  effects: EffectsChain,
): PlanetVoice {
  // Disconnect and dispose old synth
  try {
    voice.synth.disconnect();
    if (voice.synth instanceof Tone.Synth) voice.synth.dispose();
    else if (voice.synth instanceof Tone.FMSynth) voice.synth.dispose();
    else if (voice.synth instanceof Tone.PluckSynth) voice.synth.dispose();
    else if (voice.synth instanceof Tone.Filter) voice.synth.dispose();
  } catch {
    // Best effort
  }

  // Create new synth
  const synth = createSynth(newType);
  synth.connect(voice.gainNode);

  return { ...voice, synth, synthType: newType };
}

/**
 * Main Audio Engine class.
 * Manages Tone.js startup, voice map, trigger event handling, and master output.
 */

import * as Tone from 'tone';
import type { TriggerEvent } from './types.js';
import { EffectsChain } from './effects.js';
import { createVoice, disposeVoice, updateVoiceSynth, triggerNote } from './planet-voice.js';
import { generateNoteArray, midiToFrequency } from './scales.js';
import { distanceToNote } from './quantizer.js';
import type { SynthType } from './types.js';
import { lerp } from '../lib/math.js';
import type { PlanetVoice } from './planet-voice.js';

export class AudioEngine {
  private effects: EffectsChain;
  private voices = new Map<string, PlanetVoice>();
  private scaleNotes: number[] = [];
  private started = false;
  private triggerCount = 0;
  private triggerCountStartTime = 0;

  constructor() {
    this.effects = new EffectsChain();
    this.triggerCountStartTime = performance.now();
    this.updateScale('C', 'lydian', 3, 5);
  }

  /** Initialize the audio context (must be called from a user gesture) */
  async start(): Promise<void> {
    if (this.started) return;
    await Tone.start();
    this.started = true;
  }

  /** Update the scale used for pitch quantization */
  updateScale(root: string, mode: string, octaveMin: number, octaveMax: number): void {
    this.scaleNotes = generateNoteArray(root, mode as never, octaveMin, octaveMax);
  }

  /** Create a new voice for a planet */
  addVoice(planetId: string, synthType: SynthType): void {
    if (this.voices.has(planetId)) return;
    const voice = createVoice(planetId, synthType, this.effects);
    this.voices.set(planetId, voice);
  }

  /** Remove a planet's voice */
  removeVoice(planetId: string): void {
    const voice = this.voices.get(planetId);
    if (voice) {
      disposeVoice(voice);
      this.voices.delete(planetId);
    }
  }

  /** Update a planet's synth type */
  updateSynthType(planetId: string, synthType: SynthType): void {
    const voice = this.voices.get(planetId);
    if (voice) {
      const updated = updateVoiceSynth(voice, synthType, this.effects);
      this.voices.set(planetId, updated);
    }
  }

  /** Set per-planet volume (0-1) */
  setPlanetVolume(planetId: string, volume: number): void {
    const voice = this.voices.get(planetId);
    if (voice) {
      voice.gainNode.gain.value = volume;
    }
  }

  /** Set per-planet pan (-1 to 1) */
  setPlanetPan(planetId: string, pan: number): void {
    const voice = this.voices.get(planetId);
    if (voice) {
      voice.panNode.pan.value = pan;
    }
  }

  /** Mute a planet (gain=0, keep synth alive) */
  mutePlanet(planetId: string, muted: boolean): void {
    const voice = this.voices.get(planetId);
    if (voice) {
      voice.gainNode.gain.value = muted ? 0 : 0.75;
    }
  }

  /** Handle a trigger event — schedule a note */
  handleTrigger(event: TriggerEvent): void {
    if (!this.started) return;
    if (this.scaleNotes.length === 0) return;

    const voice = this.voices.get(event.planetId);
    if (!voice) return;

    // Distance → pitch
    const midiNote = distanceToNote(event.distance, this.scaleNotes);
    const frequency = midiToFrequency(midiNote);

    // Velocity → volume: lerp(0.2, 1.0, normalizedVelocity)
    const maxVel = 10; // typical max velocity in simulation units
    const normalizedVel = Math.min(event.velocity / maxVel, 1);
    const volume = lerp(0.2, 1.0, normalizedVel);

    // Angle → pan: cos(angle) maps to [-1, 1]
    const pan = Math.cos(event.angle);

    voice.panNode.pan.value = pan;

    // Trigger note
    triggerNote(voice, frequency, '8n', volume, normalizedVel);

    this.triggerCount++;
  }

  /** Update effects settings */
  setReverbMix(wet: number): void {
    this.effects.setReverbMix(wet);
  }

  setDelayMix(wet: number): void {
    this.effects.setDelayMix(wet);
  }

  setMasterVolume(volume: number): void {
    this.effects.setMasterVolume(volume);
  }

  /** Get triggers per minute (rolling average) */
  getTriggersPerMinute(): number {
    const elapsed = (performance.now() - this.triggerCountStartTime) / 60000;
    if (elapsed < 0.01) return 0;
    return this.triggerCount / elapsed;
  }

  /** Dispose all audio resources */
  dispose(): void {
    for (const voice of this.voices.values()) {
      disposeVoice(voice);
    }
    this.voices.clear();
    this.effects.dispose();
  }
}

/**
 * Renderer type definitions.
 */

export interface RenderConfig {
  trailFadeRate: number;
  showTrails: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
  radius: number;
  color: string;
  active: boolean;
}

export interface Ripple {
  x: number;
  y: number;
  radius: number;
  maxRadius: number;
  life: number;
  maxLife: number;
  color: string;
  lineWidth: number;
  active: boolean;
}

export interface VisualEvent {
  type: 'trigger';
  x: number;
  y: number;
  planetColor: string;
  planetRadius: number;
}

/**
 * Background renderer — starfield and nebula.
 * Both pre-rendered to offscreen canvases for performance.
 */

export class Background {
  private starCanvas: OffscreenCanvas | HTMLCanvasElement;
  private nebulaCanvas: OffscreenCanvas | HTMLCanvasElement;
  private starCtx: CanvasRenderingContext2D;
  private nebulaCtx: CanvasRenderingContext2D;
  private width = 0;
  private height = 0;

  constructor() {
    // Use OffscreenCanvas where available, fallback to regular canvas
    this.starCanvas = typeof OffscreenCanvas !== 'undefined'
      ? new OffscreenCanvas(1, 1)
      : document.createElement('canvas');
    this.nebulaCanvas = typeof OffscreenCanvas !== 'undefined'
      ? new OffscreenCanvas(1, 1)
      : document.createElement('canvas');

    const starCtx = this.starCanvas.getContext('2d')!;
    const nebulaCtx = this.nebulaCanvas.getContext('2d')!;
    if (!starCtx || !nebulaCtx) throw new Error('Could not create background contexts');
    this.starCtx = starCtx as CanvasRenderingContext2D;
    this.nebulaCtx = nebulaCtx as CanvasRenderingContext2D;
  }

  /** Regenerate backgrounds for new canvas dimensions */
  resize(width: number, height: number): void {
    this.width = width;
    this.height = height;

    this.starCanvas.width = width;
    this.starCanvas.height = height;
    this.nebulaCanvas.width = width;
    this.nebulaCanvas.height = height;

    this.drawStarfield();
    this.drawNebula();
  }

  private drawStarfield(): void {
    const ctx = this.starCtx;
    ctx.fillStyle = '#0a0a14';
    ctx.fillRect(0, 0, this.width, this.height);

    for (let i = 0; i < 200; i++) {
      const x = Math.random() * this.width;
      const y = Math.random() * this.height;
      const radius = 0.5 + Math.random() * 1.5;
      const brightness = 0.3 + Math.random() * 0.7;
      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(255, 255, 255, ${brightness})`;
      ctx.fill();
    }
  }

  private drawNebula(): void {
    const ctx = this.nebulaCtx;
    ctx.clearRect(0, 0, this.width, this.height);

    // 2-3 radial gradient blobs at random positions
    const blobs = [
      { x: this.width * 0.3, y: this.height * 0.4, r: Math.max(this.width, this.height) * 0.4, color: [20, 30, 80] },
      { x: this.width * 0.7, y: this.height * 0.6, r: Math.max(this.width, this.height) * 0.35, color: [60, 20, 60] },
      { x: this.width * 0.5, y: this.height * 0.3, r: Math.max(this.width, this.height) * 0.3, color: [10, 40, 50] },
    ];

    for (const blob of blobs) {
      const grad = ctx.createRadialGradient(blob.x, blob.y, 0, blob.x, blob.y, blob.r);
      grad.addColorStop(0, `rgba(${blob.color[0]}, ${blob.color[1]}, ${blob.color[2]}, 0.1)`);
      grad.addColorStop(1, `rgba(${blob.color[0]}, ${blob.color[1]}, ${blob.color[2]}, 0)`);
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, this.width, this.height);
    }
  }

  /** Draw the composited background to the main canvas */
  draw(ctx: CanvasRenderingContext2D): void {
    if (this.width === 0) return;
    ctx.drawImage(this.starCanvas as HTMLCanvasElement, 0, 0);
    ctx.drawImage(this.nebulaCanvas as HTMLCanvasElement, 0, 0);
  }
}

/**
 * Fading trail overlay renderer.
 * Uses alpha-fill technique: O(1) per frame, no history arrays.
 */

export class Trails {
  private fadeRate = 0.03;

  /** Set the trail fade rate (0.01 = long, 0.1 = short) */
  setFadeRate(rate: number): void {
    this.fadeRate = rate;
  }

  /** Apply the fading overlay */
  drawFadeOverlay(ctx: CanvasRenderingContext2D, width: number, height: number): void {
    ctx.fillStyle = `rgba(0, 0, 0, ${this.fadeRate})`;
    ctx.fillRect(0, 0, width, height);
  }

  /** Draw trail dots for a planet at its current position */
  drawTrailDot(
    ctx: CanvasRenderingContext2D,
    x: number,
    y: number,
    color: string,
    _radius: number = 2,
  ): void {
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    ctx.beginPath();
    ctx.arc(x, y, 2, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.globalAlpha = 0.6;
    ctx.fill();
    ctx.restore();
  }
}

/**
 * Body rendering — sun and planets with glow effects.
 */

import type { Body } from '../simulation/types.js';
import { hexToRgba } from '../lib/colors.js';

/** Render the sun with radial gradient glow and pulsing animation */
export function drawSun(ctx: CanvasRenderingContext2D, sun: Body, time: number): void {
  const pulseOffset = Math.sin(time * 0.001 * Math.PI * 2 / 4) * 2; // ~4s period
  const radius = sun.radius + pulseOffset;

  ctx.save();
  ctx.globalCompositeOperation = 'lighter';

  // Outer glow
  const glowGrad = ctx.createRadialGradient(
    sun.position.x, sun.position.y, 0,
    sun.position.x, sun.position.y, radius * 3,
  );
  glowGrad.addColorStop(0, 'rgba(255, 213, 79, 0.3)');
  glowGrad.addColorStop(1, 'rgba(255, 143, 0, 0)');
  ctx.fillStyle = glowGrad;
  ctx.beginPath();
  ctx.arc(sun.position.x, sun.position.y, radius * 3, 0, Math.PI * 2);
  ctx.fill();

  // Core
  const coreGrad = ctx.createRadialGradient(
    sun.position.x, sun.position.y, 0,
    sun.position.x, sun.position.y, radius,
  );
  coreGrad.addColorStop(0, '#ffffff');
  coreGrad.addColorStop(0.3, '#ffd54f');
  coreGrad.addColorStop(0.7, '#ff8f00');
  coreGrad.addColorStop(1, 'transparent');
  ctx.fillStyle = coreGrad;
  ctx.beginPath();
  ctx.arc(sun.position.x, sun.position.y, radius, 0, Math.PI * 2);
  ctx.fill();

  ctx.restore();
}

/** Render a planet with glow */
export function drawPlanet(ctx: CanvasRenderingContext2D, body: Body): void {
  const { position, radius, color } = body;

  ctx.save();
  ctx.globalCompositeOperation = 'lighter';

  // Outer glow (2× radius)
  const glowGrad = ctx.createRadialGradient(
    position.x, position.y, 0,
    position.x, position.y, radius * 2,
  );
  glowGrad.addColorStop(0, hexToRgba(color, 0.4));
  glowGrad.addColorStop(1, hexToRgba(color, 0));
  ctx.fillStyle = glowGrad;
  ctx.beginPath();
  ctx.arc(position.x, position.y, radius * 2, 0, Math.PI * 2);
  ctx.fill();

  // Core with white center
  const coreGrad = ctx.createRadialGradient(
    position.x, position.y, 0,
    position.x, position.y, radius,
  );
  coreGrad.addColorStop(0, 'rgba(255, 255, 255, 0.9)');
  coreGrad.addColorStop(0.4, hexToRgba(color, 0.8));
  coreGrad.addColorStop(1, hexToRgba(color, 0.3));
  ctx.fillStyle = coreGrad;
  ctx.beginPath();
  ctx.arc(position.x, position.y, radius, 0, Math.PI * 2);
  ctx.fill();

  ctx.restore();

  // Dimming indicator for escaped planets
  if (body.escapedAt > 0) {
    ctx.save();
    ctx.globalAlpha = 0.3;
    ctx.fillStyle = '#0a0a14';
    ctx.beginPath();
    ctx.arc(position.x, position.y, radius + 2, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
}

/**
 * Trigger line rendering — subtle glowing lines through the sun.
 */

import type { TriggerLineState } from '../state/types.js';

export function drawTriggerLines(
  ctx: CanvasRenderingContext2D,
  lines: TriggerLineState[],
  sunX: number,
  sunY: number,
  canvasWidth: number,
  canvasHeight: number,
  selectedLineId: string | null,
): void {
  const diag = Math.sqrt(canvasWidth * canvasWidth + canvasHeight * canvasHeight);

  for (const line of lines) {
    const isSelected = line.id === selectedLineId;
    const alpha = isSelected ? 0.4 : 0.15;

    ctx.save();
    ctx.strokeStyle = `rgba(100, 150, 255, ${alpha})`;
    ctx.lineWidth = 1;
    ctx.beginPath();

    // Line from sun extending in both directions at the given angle
    const dx = Math.cos(line.angle) * diag;
    const dy = Math.sin(line.angle) * diag;
    ctx.moveTo(sunX - dx, sunY - dy);
    ctx.lineTo(sunX + dx, sunY + dy);
    ctx.stroke();

    // Draw rotation handles if selected
    if (isSelected) {
      const handleDist = Math.min(canvasWidth, canvasHeight) / 2 - 20;
      const hx1 = sunX + Math.cos(line.angle) * handleDist;
      const hy1 = sunY + Math.sin(line.angle) * handleDist;
      const hx2 = sunX - Math.cos(line.angle) * handleDist;
      const hy2 = sunY - Math.sin(line.angle) * handleDist;

      ctx.fillStyle = 'rgba(100, 150, 255, 0.5)';
      ctx.beginPath();
      ctx.arc(hx1, hy1, 6, 0, Math.PI * 2);
      ctx.fill();
      ctx.beginPath();
      ctx.arc(hx2, hy2, 6, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
  }
}

/**
 * Particle system with object pooling (~200 pre-allocated).
 * Burst of 8-12 particles on trigger events.
 */

import type { Particle } from './types.js';

const POOL_SIZE = 200;
const PARTICLES_PER_BURST_MIN = 8;
const PARTICLES_PER_BURST_MAX = 12;

export class ParticleSystem {
  private pool: Particle[] = [];
  private performanceLevel: 'full' | 'reduced' | 'off' = 'full';

  constructor() {
    // Pre-allocate particle pool
    for (let i = 0; i < POOL_SIZE; i++) {
      this.pool.push({
        x: 0, y: 0,
        vx: 0, vy: 0,
        life: 0, maxLife: 0,
        radius: 0,
        color: '',
        active: false,
      });
    }
  }

  /** Set performance level based on frame time */
  setPerformanceLevel(frameTimeMs: number): void {
    if (frameTimeMs > 30) {
      this.performanceLevel = 'off';
    } else if (frameTimeMs > 20) {
      this.performanceLevel = 'reduced';
    } else {
      this.performanceLevel = 'full';
    }
  }

  /** Emit a burst of particles at the given position */
  burst(x: number, y: number, color: string, count?: number): void {
    if (this.performanceLevel === 'off') return;

    const n = count ??
      (this.performanceLevel === 'reduced'
        ? 4
        : PARTICLES_PER_BURST_MIN + Math.floor(Math.random() * (PARTICLES_PER_BURST_MAX - PARTICLES_PER_BURST_MIN + 1)));

    let spawned = 0;
    for (const particle of this.pool) {
      if (spawned >= n) break;
      if (particle.active) continue;

      const angle = Math.random() * Math.PI * 2;
      const speed = 1 + Math.random() * 3;
      const life = 300 + Math.random() * 200; // 300-500ms

      particle.x = x;
      particle.y = y;
      particle.vx = Math.cos(angle) * speed;
      particle.vy = Math.sin(angle) * speed;
      particle.life = life;
      particle.maxLife = life;
      particle.radius = 1 + Math.random() * 2;
      particle.color = color;
      particle.active = true;
      spawned++;
    }
  }

  /** Update all active particles */
  update(dt: number): void {
    for (const p of this.pool) {
      if (!p.active) continue;

      p.life -= dt * 1000;
      if (p.life <= 0) {
        p.active = false;
        continue;
      }

      // Velocity damping
      p.vx *= 0.95;
      p.vy *= 0.95;
      p.x += p.vx;
      p.y += p.vy;
    }
  }

  /** Draw all active particles */
  draw(ctx: CanvasRenderingContext2D): void {
    if (this.performanceLevel === 'off') return;

    ctx.save();
    ctx.globalCompositeOperation = 'lighter';

    for (const p of this.pool) {
      if (!p.active) continue;
      const alpha = p.life / p.maxLife;
      ctx.globalAlpha = alpha;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
  }
}

/**
 * Visual effects — trigger ripples, sun flash, selection ring.
 */

import type { Ripple } from './types.js';
import { hexToRgba } from '../lib/colors.js';

export class Effects {
  private ripples: Ripple[] = [];
  private sunFlashTime = 0;
  private sunFlashDuration = 200;

  /** Create a ripple at a trigger crossing point */
  addRipple(x: number, y: number, planetRadius: number, planetColor: string): void {
    this.ripples.push({
      x,
      y,
      radius: planetRadius,
      maxRadius: 40,
      life: 400,
      maxLife: 400,
      color: planetColor,
      lineWidth: 2,
      active: true,
    });
    this.sunFlashTime = this.sunFlashDuration;
  }

  /** Trigger sun flash */
  flashSun(): void {
    this.sunFlashTime = this.sunFlashDuration;
  }

  /** Update all active effects */
  update(dtMs: number): void {
    // Update ripples
    for (const r of this.ripples) {
      if (!r.active) continue;
      r.life -= dtMs;
      if (r.life <= 0) {
        r.active = false;
        continue;
      }
      const progress = 1 - r.life / r.maxLife;
      r.radius = r.x !== undefined ? r.radius : 0; // keep reference
      // Interpolate radius from start to max
      const startRadius = r.maxRadius * (1 - (r.maxLife / r.maxLife)); // always 0 logic; let's fix
    }

    // Actually update ripple radii properly
    for (const r of this.ripples) {
      if (!r.active) continue;
      const progress = 1 - r.life / r.maxLife;
      // Overwrite the radius to interpolate
      (r as { _currentRadius: number })._currentRadius =
        (1 - progress) * 0 + progress * r.maxRadius; // from 0 to maxRadius
    }

    // Sun flash decay
    if (this.sunFlashTime > 0) {
      this.sunFlashTime = Math.max(0, this.sunFlashTime - dtMs);
    }
  }

  /** Draw all effects */
  draw(ctx: CanvasRenderingContext2D, sunX: number, sunY: number, sunRadius: number): void {
    // Draw ripples
    for (const r of this.ripples) {
      if (!r.active) continue;
      const progress = 1 - r.life / r.maxLife;
      const currentRadius = progress * r.maxRadius;
      const alpha = (1 - progress) * 0.6;

      ctx.save();
      ctx.strokeStyle = hexToRgba(r.color, alpha);
      ctx.lineWidth = r.lineWidth;
      ctx.beginPath();
      ctx.arc(r.x, r.y, currentRadius, 0, Math.PI * 2);
      ctx.stroke();
      ctx.restore();
    }

    // Clean up inactive ripples periodically
    this.ripples = this.ripples.filter((r) => r.active);

    // Sun flash
    if (this.sunFlashTime > 0) {
      const flashAlpha = (this.sunFlashTime / this.sunFlashDuration) * 0.2;
      ctx.save();
      ctx.globalCompositeOperation = 'lighter';
      ctx.fillStyle = `rgba(255, 255, 200, ${flashAlpha})`;
      ctx.beginPath();
      ctx.arc(sunX, sunY, sunRadius * 2, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    }
  }

  /** Draw selection ring around a planet */
  drawSelectionRing(
    ctx: CanvasRenderingContext2D,
    x: number,
    y: number,
    radius: number,
    time: number,
  ): void {
    // Pulsing ring: opacity oscillates 100% → 30% → 100% over 1s
    const pulse = 0.65 + 0.35 * Math.sin(time * 0.001 * Math.PI * 2);
    ctx.save();
    ctx.strokeStyle = `rgba(255, 255, 255, ${pulse})`;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(x, y, radius + 6, 0, Math.PI * 2);
    ctx.stroke();
    ctx.restore();
  }
}

/**
 * Main Renderer class.
 * Manages the canvas, render loop, and drawing order per spec §04.10.
 */

import type { Body } from '../simulation/types.js';
import type { TriggerLineState } from '../state/types.js';
import type { VisualEvent } from './types.js';
import { Background } from './background.js';
import { Trails } from './trails.js';
import { drawSun, drawPlanet } from './bodies.js';
import { drawTriggerLines } from './triggers-vis.js';
import { ParticleSystem } from './particles.js';
import { Effects } from './effects.js';

export class Renderer {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private background: Background;
  private trails: Trails;
  private particles: ParticleSystem;
  private effects: Effects;
  private width = 0;
  private height = 0;
  private dpr = 1;
  private time = 0;
  private lastFrameTime = 0;
  private frameTime = 0;

  constructor(canvas: HTMLCanvasElement) {
    this.canvas = canvas;
    const ctx = canvas.getContext('2d')!;
    if (!ctx) throw new Error('Could not get 2D context');
    this.ctx = ctx;
    this.background = new Background();
    this.trails = new Trails();
    this.particles = new ParticleSystem();
    this.effects = new Effects();
  }

  /** Set up canvas dimensions for the current window size */
  resize(): void {
    this.dpr = window.devicePixelRatio || 1;
    this.width = window.innerWidth;
    this.height = window.innerHeight;
    this.canvas.width = this.width * this.dpr;
    this.canvas.height = this.height * this.dpr;
    this.canvas.style.width = `${this.width}px`;
    this.canvas.style.height = `${this.height}px`;
    this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);
    this.background.resize(this.width, this.height);
  }

  /** Set trail fade rate */
  setTrailFadeRate(rate: number): void {
    this.trails.setFadeRate(rate);
  }

  /**
   * Main render call — draws everything for one frame.
   * Rendering order per spec §04.10:
   * 1. Background (starfield + nebula)
   * 2. Trail fade overlay
   * 3. Trigger lines
   * 4. Trail dots
   * 5. Ripples/particles
   * 6. Sun
   * 7. Planets
   * 8. Spawn gesture
   * 9. Selection ring
   */
  render(
    bodies: Body[],
    triggerLines: TriggerLineState[],
    selectedPlanetId: string | null,
    selectedTriggerLineId: string | null,
    spawnGesture: { x: number; y: number; endX: number; endY: number; active: boolean } | null,
    visualEvents: VisualEvent[],
    dt: number,
  ): void {
    const now = performance.now();
    this.frameTime = now - this.lastFrameTime;
    this.lastFrameTime = now;
    this.time = now;

    // Update performance-sensitive systems
    this.particles.setPerformanceLevel(this.frameTime);
    this.effects.update(dt);
    this.particles.update(dt);

    // Process visual events
    for (const evt of visualEvents) {
      if (evt.type === 'trigger') {
        this.particles.burst(evt.x, evt.y, evt.planetColor);
        this.effects.addRipple(evt.x, evt.y, evt.planetRadius, evt.planetColor);
      }
    }

    const ctx = this.ctx;

    // 1. Background
    this.background.draw(ctx);

    // 2. Trail fade overlay
    this.trails.drawFadeOverlay(ctx, this.width, this.height);

    // 3. Trigger lines
    const sun = bodies.find((b) => b.isAnchor);
    if (sun) {
      drawTriggerLines(ctx, triggerLines, sun.position.x, sun.position.y, this.width, this.height, selectedTriggerLineId);
    }

    // 4. Trail dots (current positions)
    ctx.save();
    for (const body of bodies) {
      if (body.isAnchor) continue;
      this.trails.drawTrailDot(ctx, body.position.x, body.position.y, body.color);
    }
    ctx.restore();

    // 5. Ripples and particles
    if (sun) {
      this.effects.draw(ctx, sun.position.x, sun.position.y, sun.radius);
    }
    this.particles.draw(ctx);

    // 6. Sun
    if (sun) {
      drawSun(ctx, sun, now);
    }

    // 7. Planets
    for (const body of bodies) {
      if (body.isAnchor) continue;
      drawPlanet(ctx, body);
    }

    // 8. Spawn gesture
    if (spawnGesture?.active) {
      this.drawSpawnGesture(ctx, spawnGesture);
    }

    // 9. Selection ring
    if (selectedPlanetId) {
      const selected = bodies.find((b) => b.id === selectedPlanetId);
      if (selected) {
        this.effects.drawSelectionRing(ctx, selected.position.x, selected.position.y, selected.radius, now);
      }
    }
  }

  private drawSpawnGesture(
    ctx: CanvasRenderingContext2D,
    gesture: { x: number; y: number; endX: number; endY: number; active: boolean },
  ): void {
    // Ghost planet
    ctx.save();
    ctx.globalAlpha = 0.4;
    ctx.fillStyle = '#4fc3f7';
    ctx.beginPath();
    ctx.arc(gesture.x, gesture.y, 8, 0, Math.PI * 2);
    ctx.fill();

    // Velocity vector (rubber band)
    const dx = gesture.endX - gesture.x;
    const dy = gesture.endY - gesture.y;
    const length = Math.sqrt(dx * dx + dy * dy);

    // Color gradient: white → green by length
    const greenness = Math.min(length / 200, 1);
    ctx.strokeStyle = `rgb(${Math.round(255 * (1 - greenness))}, 255, ${Math.round(255 * (1 - greenness))})`;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(gesture.x, gesture.y);
    ctx.lineTo(gesture.endX, gesture.endY);
    ctx.stroke();

    // Arrowhead
    if (length > 10) {
      const angle = Math.atan2(dy, dx);
      const arrowLen = 10;
      ctx.beginPath();
      ctx.moveTo(gesture.endX, gesture.endY);
      ctx.lineTo(
        gesture.endX - arrowLen * Math.cos(angle - 0.4),
        gesture.endY - arrowLen * Math.sin(angle - 0.4),
      );
      ctx.moveTo(gesture.endX, gesture.endY);
      ctx.lineTo(
        gesture.endX - arrowLen * Math.cos(angle + 0.4),
        gesture.endY - arrowLen * Math.sin(angle + 0.4),
      );
      ctx.stroke();
    }

    ctx.restore();
  }

  get lastFrameTimeMs(): number {
    return this.frameTime;
  }
}

/**
 * Planet selection state management.
 */

import type { Body } from '../simulation/types.js';

let selectedPlanetId: string | null = null;

export function getSelectedPlanetId(): string | null {
  return selectedPlanetId;
}

export function setSelectedPlanetId(id: string | null): void {
  selectedPlanetId = id;
}

/** Find a planet body at the given canvas coordinates (within radius + 5px tolerance) */
export function findPlanetAt(bodies: Body[], x: number, y: number): Body | null {
  // Check in reverse order so topmost (latest) planet is selected first
  for (let i = bodies.length - 1; i >= 0; i--) {
    const body = bodies[i];
    if (body.isAnchor) continue;
    const dx = body.position.x - x;
    const dy = body.position.y - y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist <= body.radius + 5) {
      return body;
    }
  }
  return null;
}

/**
 * Sidebar — planet list with mute/solo/delete controls.
 * DOM-based UI built with vanilla TypeScript.
 */

import type { Body } from '../simulation/types.js';
import type { SynthType } from '../audio/types.js';
import { SYNTH_LABELS } from '../audio/types.js';

export interface SidebarCallbacks {
  onSelectPlanet: (id: string | null) => void;
  onMutePlanet: (id: string) => void;
  onSoloPlanet: (id: string) => void;
  onDeletePlanet: (id: string) => void;
}

export class Sidebar {
  private container: HTMLElement;
  private listEl: HTMLElement;
  private emptyEl: HTMLElement;
  private callbacks: SidebarCallbacks;

  constructor(container: HTMLElement, callbacks: SidebarCallbacks) {
    this.container = container;
    this.callbacks = callbacks;

    this.container.innerHTML = '';

    // Title
    const title = document.createElement('div');
    title.className = 'panel-section-title';
    title.textContent = 'PLANETS';
    this.container.appendChild(title);

    // Planet list
    this.listEl = document.createElement('ul');
    this.listEl.className = 'planet-list';
    this.container.appendChild(this.listEl);

    // Empty state
    this.emptyEl = document.createElement('div');
    this.emptyEl.className = 'empty-state';
    this.emptyEl.textContent = 'Click and drag on the canvas to spawn a planet.';
    this.container.appendChild(this.emptyEl);

    // Editor container (populated when planet selected)
    this.editorEl = document.createElement('div');
    this.editorEl.className = 'planet-editor';
    this.editorEl.style.display = 'none';
    this.container.appendChild(this.editorEl);
  }

  private editorEl: HTMLElement;

  /** Update the sidebar to reflect current bodies and selection */
  update(bodies: Body[], selectedId: string | null): void {
    const planets = bodies.filter((b) => !b.isAnchor);

    // Toggle empty state
    this.emptyEl.style.display = planets.length === 0 ? 'block' : 'none';

    // Rebuild list
    this.listEl.innerHTML = '';

    for (const planet of planets) {
      const row = document.createElement('li');
      row.className = 'planet-row' +
        (planet.id === selectedId ? ' selected' : '') +
        (planet.muted ? ' muted' : '');
      row.style.borderLeftColor = planet.id === selectedId ? planet.color : 'transparent';

      // Color dot
      const dot = document.createElement('span');
      dot.className = 'planet-color-dot';
      dot.style.background = planet.color;
      row.appendChild(dot);

      // Name
      const name = document.createElement('span');
      name.className = 'planet-name';
      name.textContent = planet.name;
      row.appendChild(name);

      // Synth label
      const synthLabel = document.createElement('span');
      synthLabel.className = 'planet-synth-label';
      // We'll use a data attribute to store the synth type
      synthLabel.textContent = 'FM'; // default, updated from state
      row.appendChild(synthLabel);

      // Mute button
      const muteBtn = document.createElement('button');
      muteBtn.className = 'planet-btn' + (planet.muted ? ' active' : '');
      muteBtn.textContent = planet.muted ? '🔇' : '🔈';
      muteBtn.title = 'Mute';
      muteBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        this.callbacks.onMutePlanet(planet.id);
      });
      row.appendChild(muteBtn);

      // Solo button
      const soloBtn = document.createElement('button');
      soloBtn.className = 'planet-btn' + (planet.soloed ? ' active' : '');
      soloBtn.textContent = planet.soloed ? '🎯' : '◎';
      soloBtn.title = 'Solo';
      soloBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        this.callbacks.onSoloPlanet(planet.id);
      });
      row.appendChild(soloBtn);

      // Delete button
      const deleteBtn = document.createElement('button');
      deleteBtn.className = 'planet-btn delete';
      deleteBtn.textContent = '✕';
      deleteBtn.title = 'Delete';
      deleteBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        this.callbacks.onDeletePlanet(planet.id);
      });
      row.appendChild(deleteBtn);

      // Click row to select
      row.addEventListener('click', () => {
        this.callbacks.onSelectPlanet(planet.id);
      });

      this.listEl.appendChild(row);
    }
  }

  /** Update the planet editor panel for the selected planet */
  updateEditor(
    planet: Body | null,
    synthType: SynthType,
    volume: number,
    pan: number,
    onChangeSynth: (type: SynthType) => void,
    onChangeVolume: (vol: number) => void,
    onChangePan: (pan: number) => void,
    onChangeMass: (mass: number) => void,
    onChangeColor: (color: string) => void,
  ): void {
    if (!planet) {
      this.editorEl.style.display = 'none';
      return;
    }

    this.editorEl.style.display = 'block';
    this.editorEl.innerHTML = '';

    const title = document.createElement('div');
    title.className = 'panel-section-title';
    title.textContent = 'PLANET SETTINGS';
    this.editorEl.appendChild(title);

    // Synth dropdown
    const synthRow = this.createControlRow('Synth Engine');
    const synthSelect = document.createElement('select');
    for (const type of ['sine', 'triangle', 'sawtooth', 'square', 'fm', 'marimba', 'bell', 'pluck'] as SynthType[]) {
      const opt = document.createElement('option');
      opt.value = type;
      opt.textContent = SYNTH_LABELS[type];
      if (type === synthType) opt.selected = true;
      synthSelect.appendChild(opt);
    }
    synthSelect.addEventListener('change', () => onChangeSynth(synthSelect.value as SynthType));
    synthRow.appendChild(synthSelect);
    this.editorEl.appendChild(synthRow);

    // Volume slider
    this.editorEl.appendChild(
      this.createSlider('Volume', volume * 100, 0, 100, (val) => onChangeVolume(val / 100)),
    );

    // Pan slider
    this.editorEl.appendChild(
      this.createSlider('Pan', (pan + 1) * 50, 0, 100, (val) => onChangePan(val / 50 - 1), 'L', 'R'),
    );

    // Mass slider
    this.editorEl.appendChild(
      this.createSlider('Mass', planet.mass, 1, 50, onChangeMass),
    );

    // Color picker
    const colorRow = this.createControlRow('Color');
    const colorInput = document.createElement('input');
    colorInput.type = 'color';
    colorInput.value = planet.color;
    colorInput.style.width = '40px';
    colorInput.style.height = '24px';
    colorInput.style.border = 'none';
    colorInput.style.background = 'none';
    colorInput.style.cursor = 'pointer';
    colorInput.addEventListener('input', () => onChangeColor(colorInput.value));
    colorRow.appendChild(colorInput);
    this.editorEl.appendChild(colorRow);
  }

  private createControlRow(label: string): HTMLElement {
    const row = document.createElement('div');
    row.className = 'control-row';
    const lbl = document.createElement('span');
    lbl.className = 'control-label';
    lbl.textContent = label;
    row.appendChild(lbl);
    return row;
  }

  private createSlider(
    label: string,
    value: number,
    min: number,
    max: number,
    onChange: (value: number) => void,
    leftLabel?: string,
    rightLabel?: string,
  ): HTMLElement {
    const container = document.createElement('div');

    const row = document.createElement('div');
    row.className = 'control-row';

    const lbl = document.createElement('span');
    lbl.className = 'control-label';
    lbl.textContent = label;
    row.appendChild(lbl);

    const val = document.createElement('span');
    val.className = 'control-value';
    val.textContent = leftLabel ? (value < 50 ? leftLabel : value > 50 ? rightLabel || '' : 'C') : String(Math.round(value));
    row.appendChild(val);

    container.appendChild(row);

    const slider = document.createElement('input');
    slider.type = 'range';
    slider.min = String(min);
    slider.max = String(max);
    slider.value = String(value);
    slider.addEventListener('input', () => {
      const v = parseFloat(slider.value);
      val.textContent = leftLabel ? (v < 50 ? leftLabel : v > 50 ? rightLabel || '' : 'C') : String(Math.round(v));
      onChange(v);
    });
    container.appendChild(slider);

    return container;
  }
}

