/**
 * Click+drag spawn interaction handler.
 * Creates a ghost planet preview, velocity vector (rubber band), and spawns on release.
 */

import type { Vector2 } from '../lib/math.js';
import { vec2, sub, scale } from '../lib/math.js';
import { VELOCITY_MULTIPLIER, MIN_MASS, MAX_MASS } from '../simulation/constants.js';

export interface SpawnState {
  active: boolean;
  startX: number;
  startY: number;
  endX: number;
  endY: number;
}

export interface SpawnCallbacks {
  onSpawn: (position: Vector2, velocity: Vector2, mass: number) => void;
  getDefaultMass: () => number;
}

export class SpawnHandler {
  private canvas: HTMLCanvasElement;
  private callbacks: SpawnCallbacks;
  state: SpawnState = { active: false, startX: 0, startY: 0, endX: 0, endY: 0 };

  constructor(canvas: HTMLCanvasElement, callbacks: SpawnCallbacks) {
    this.canvas = canvas;
    this.callbacks = callbacks;
    this.attach();
  }

  private attach(): void {
    this.canvas.addEventListener('mousedown', (e) => {
      if (e.button !== 0) return; // left click only
      // Only spawn if not clicking on a planet or UI element
      this.state = {
        active: true,
        startX: e.clientX,
        startY: e.clientY,
        endX: e.clientX,
        endY: e.clientY,
      };
    });

    this.canvas.addEventListener('mousemove', (e) => {
      if (!this.state.active) return;
      this.state.endX = e.clientX;
      this.state.endY = e.clientY;
    });

    this.canvas.addEventListener('mouseup', (e) => {
      if (!this.state.active) return;
      if (e.button !== 0) return;

      this.state.active = false;

      const dx = this.state.startX - this.state.endX;
      const dy = this.state.startY - this.state.endY;
      const length = Math.sqrt(dx * dx + dy * dy);

      // Only spawn if there's a meaningful drag
      if (length > 5) {
        const position = vec2(this.state.startX, this.state.startY);
        // Slingshot: inverted drag direction, scaled by velocity multiplier
        const velocity = scale(sub(
          vec2(this.state.startX, this.state.startY),
          vec2(this.state.endX, this.state.endY),
        ), VELOCITY_MULTIPLIER);
        const mass = this.callbacks.getDefaultMass();

        this.callbacks.onSpawn(position, velocity, mass);
      }
    });
  }

  /** Cancel any active spawn gesture */
  cancel(): void {
    this.state.active = false;
  }
}

/**
 * Trigger line interaction — click to select, drag handles to rotate.
 */

import type { TriggerLineState } from '../state/types.js';

export interface TriggerLineCallbacks {
  onSelectLine: (id: string | null) => void;
  onRotateLine: (id: string, angle: number) => void;
}

export class TriggerLineInteraction {
  private canvas: HTMLCanvasElement;
  private callbacks: TriggerLineCallbacks;
  private lines: TriggerLineState[] = [];
  private sunX = 0;
  private sunY = 0;
  private dragging: string | null = null;

  constructor(canvas: HTMLCanvasElement, callbacks: TriggerLineCallbacks) {
    this.canvas = canvas;
    this.callbacks = callbacks;
    this.attach();
  }

  /** Update trigger lines and sun position */
  update(lines: TriggerLineState[], sunX: number, sunY: number): void {
    this.lines = lines;
    this.sunX = sunX;
    this.sunY = sunY;
  }

  private attach(): void {
    this.canvas.addEventListener('mousedown', (e) => {
      // Check if near a trigger line
      const result = this.findNearLine(e.clientX, e.clientY);
      if (result) {
        this.dragging = result.lineId;
        this.callbacks.onSelectLine(result.lineId);
      }
    });

    this.canvas.addEventListener('mousemove', (e) => {
      if (!this.dragging) return;
      // Compute angle from sun to mouse
      const dx = e.clientX - this.sunX;
      const dy = e.clientY - this.sunY;
      const angle = Math.atan2(dy, dx);
      this.callbacks.onRotateLine(this.dragging, angle);
    });

    this.canvas.addEventListener('mouseup', () => {
      this.dragging = null;
    });
  }

  private findNearLine(x: number, y: number): { lineId: string } | null {
    const threshold = 10;

    for (const line of this.lines) {
      // Signed distance from point to line through sun at given angle
      const nx = Math.sin(line.angle);
      const ny = -Math.cos(line.angle);
      const dx = x - this.sunX;
      const dy = y - this.sunY;
      const dist = Math.abs(dx * nx + dy * ny);

      if (dist < threshold) {
        return { lineId: line.id };
      }
    }

    return null;
  }
}

/**
 * Keyboard shortcuts handler.
 * Per spec §05.8.
 */

export interface KeyboardCallbacks {
  onTogglePause: () => void;
  onDeleteSelected: () => void;
  onMuteSelected: () => void;
  onSoloSelected: () => void;
  onSetSynth: (index: number) => void;
  onToggleNBody: () => void;
  onResetAll: () => void;
  onTogglePanels: () => void;
  onShowShortcuts: () => void;
}

const SYNTH_MAP: Record<string, number> = {
  '1': 0, '2': 1, '3': 2, '4': 3, '5': 4, '6': 5, '7': 6, '8': 7,
};

export class KeyboardHandler {
  private callbacks: KeyboardCallbacks;

  constructor(callbacks: KeyboardCallbacks) {
    this.callbacks = callbacks;
    this.attach();
  }

  private attach(): void {
    document.addEventListener('keydown', (e) => {
      // Don't capture when typing in inputs
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLSelectElement) return;

      switch (e.key) {
        case ' ':
          e.preventDefault();
          this.callbacks.onTogglePause();
          break;
        case 'Delete':
        case 'Backspace':
          e.preventDefault();
          this.callbacks.onDeleteSelected();
          break;
        case 'm':
        case 'M':
          this.callbacks.onMuteSelected();
          break;
        case 's':
        case 'S':
          if (!e.ctrlKey && !e.metaKey) {
            this.callbacks.onSoloSelected();
          }
          break;
        case 'g':
        case 'G':
          this.callbacks.onToggleNBody();
          break;
        case 'r':
        case 'R':
          if (!e.ctrlKey && !e.metaKey) {
            this.callbacks.onResetAll();
          }
          break;
        case 'h':
        case 'H':
          this.callbacks.onTogglePanels();
          break;
        case '?':
          this.callbacks.onShowShortcuts();
          break;
        default:
          if (SYNTH_MAP[e.key] !== undefined) {
            this.callbacks.onSetSynth(SYNTH_MAP[e.key]);
          }
      }
    });
  }
}

/**
 * Status bar — bottom bar showing planet count, FPS, current scale, and triggers/min.
 */

export class StatusBar {
  private container: HTMLElement;
  private leftEl: HTMLElement;
  private centerEl: HTMLElement;
  private rightEl: HTMLElement;
  private hideTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(container: HTMLElement) {
    this.container = container;
    container.innerHTML = '';

    this.leftEl = document.createElement('span');
    this.leftEl.className = 'status-left';
    this.centerEl = document.createElement('span');
    this.centerEl.className = 'status-center';
    this.rightEl = document.createElement('span');
    this.rightEl.className = 'status-right';

    container.appendChild(this.leftEl);
    container.appendChild(this.centerEl);
    container.appendChild(this.rightEl);

    // Auto-hide after 5s inactivity
    this.scheduleHide();

    document.addEventListener('mousemove', () => this.show());
  }

  update(planetCount: number, fps: number, root: string, mode: string, triggersPerMin: number): void {
    this.leftEl.textContent = `Planets: ${planetCount}  |  FPS: ${Math.round(fps)}`;
    this.centerEl.textContent = `${root} ${mode.charAt(0).toUpperCase() + mode.slice(1)}`;
    this.rightEl.textContent = `Triggers: ${Math.round(triggersPerMin)}/min`;
  }

  private show(): void {
    this.container.classList.remove('hidden');
    this.scheduleHide();
  }

  private scheduleHide(): void {
    if (this.hideTimer) clearTimeout(this.hideTimer);
    this.hideTimer = setTimeout(() => {
      this.container.classList.add('hidden');
    }, 5000);
  }
}

/**
 * Shortcuts overlay — shows keyboard shortcuts reference.
 */

export class ShortcutsOverlay {
  private overlay: HTMLElement | null = null;

  show(): void {
    if (this.overlay) return;

    this.overlay = document.createElement('div');
    this.overlay.className = 'shortcuts-overlay';

    const content = document.createElement('div');
    content.className = 'shortcuts-content';

    const title = document.createElement('h2');
    title.textContent = 'Keyboard Shortcuts';
    content.appendChild(title);

    const shortcuts = [
      ['Space', 'Pause / Resume'],
      ['Del / ⌫', 'Delete selected planet'],
      ['M', 'Mute / Unmute selected'],
      ['S', 'Solo / Unsolo selected'],
      ['1–8', 'Set synth (sine→pluck)'],
      ['G', 'Toggle N-body gravity'],
      ['R', 'Reset all planets'],
      ['H', 'Hide / Show panels'],
      ['?', 'Show this help'],
    ];

    for (const [key, desc] of shortcuts) {
      const row = document.createElement('div');
      row.className = 'shortcut-row';
      const keyEl = document.createElement('span');
      keyEl.className = 'shortcut-key';
      keyEl.textContent = key;
      const descEl = document.createElement('span');
      descEl.className = 'shortcut-desc';
      descEl.textContent = desc;
      row.appendChild(keyEl);
      row.appendChild(descEl);
      content.appendChild(row);
    }

    this.overlay.appendChild(content);

    // Dismiss on any key or click
    const dismiss = () => this.hide();
    this.overlay.addEventListener('click', dismiss);
    const keyHandler = () => {
      document.removeEventListener('keydown', keyHandler);
      dismiss();
    };
    setTimeout(() => document.addEventListener('keydown', keyHandler), 100);

    document.body.appendChild(this.overlay);
  }

  hide(): void {
    if (this.overlay) {
      this.overlay.remove();
      this.overlay = null;
    }
  }
}

/**
 * Orbital Harmonics — Main entry point.
 * Wires simulation, renderer, audio, and UI together.
 * Single RAF loop: simulation step → trigger detection → audio scheduling → render.
 */

import './style.css';

import { Simulation } from './simulation/simulation.js';
import { Renderer } from './renderer/renderer.js';
import { AudioEngine } from './audio/engine.js';
import { TriggerDetector } from './audio/triggers.js';
import { generateNoteArray } from './audio/scales.js';
import { findPlanetAt, setSelectedPlanetId, getSelectedPlanetId } from './ui/selection.js';
import { Sidebar } from './ui/sidebar.js';
import { Controls } from './ui/controls.js';
import { SpawnHandler } from './ui/spawn.js';
import { TriggerLineInteraction } from './ui/trigger-lines.js';
import { KeyboardHandler } from './ui/keyboard.js';
import { StatusBar } from './ui/status-bar.js';
import { ShortcutsOverlay } from './ui/shortcuts-overlay.js';
import type { VisualEvent } from './renderer/types.js';
import type { SynthType, ScaleMode } from './audio/types.js';
import {
  getState, subscribe, notify,
  addPlanet as addPlanetState, removePlanet as removePlanetState,
  updatePlanet, selectPlanet, selectTriggerLine,
  updateSettings, addTriggerLine, updateTriggerLine, resetTriggerLines, resetAll,
} from './state/store.js';
import { massToRadius } from './simulation/constants.js';
import { magnitude } from './lib/math.js';

// === DOM Elements ===
const canvas = document.getElementById('canvas') as HTMLCanvasElement;
const overlay = document.getElementById('overlay') as HTMLElement;
const sidebarEl = document.getElementById('sidebar') as HTMLElement;
const controlsEl = document.getElementById('controls') as HTMLElement;
const statusBarEl = document.getElementById('status-bar') as HTMLElement;

// === Core Systems ===
const sim = new Simulation(window.innerWidth, window.innerHeight);
const renderer = new Renderer(canvas);
const audio = new AudioEngine();
const triggerDetector = new TriggerDetector(getState().triggerLines);
const shortcutsOverlay = new ShortcutsOverlay();

// === FPS tracking ===
let frameCount = 0;
let fpsTime = performance.now();
let currentFps = 60;

// === UI Setup ===
const sidebar = new Sidebar(sidebarEl, {
  onSelectPlanet: (id) => {
    selectPlanet(id);
    refreshSidebar();
  },
  onMutePlanet: (id) => {
    const body = sim.bodies.find((b) => b.id === id);
    if (body) {
      body.muted = !body.muted;
      audio.mutePlanet(id, body.muted);
      const state = getState().planets.get(id);
      if (state) updatePlanet(id, { muted: body.muted });
      refreshSidebar();
    }
  },
  onSoloPlanet: (id) => {
    const body = sim.bodies.find((b) => b.id === id);
    if (body) {
      // Toggle solo — if already soloed, unsolo. Otherwise, solo this one and unsolo others.
      const wasSoloed = body.soloed;
      for (const b of sim.planets) {
        b.soloed = false;
        audio.mutePlanet(b.id, false);
        const s = getState().planets.get(b.id);
        if (s) updatePlanet(b.id, { soloed: false });
      }
      if (!wasSoloed) {
        body.soloed = true;
        // Mute all non-soloed
        for (const b of sim.planets) {
          if (!b.soloed) {
            audio.mutePlanet(b.id, true);
            const s = getState().planets.get(b.id);
            if (s) updatePlanet(b.id, { soloed: false });
          }
        }
        const s = getState().planets.get(id);
        if (s) updatePlanet(id, { soloed: true });
      }
      refreshSidebar();
    }
  },
  onDeletePlanet: (id) => {
    deletePlanet(id);
  },
});

const controls = new Controls(controlsEl, {
  onGravityChange: (v) => { sim.G = v; updateSettings({ gravity: v }); },
  onNBodyToggle: (enabled) => { sim.nBodyEnabled = enabled; updateSettings({ nBodyEnabled: enabled }); },
  onTrailFadeChange: (v) => { renderer.setTrailFadeRate(v); updateSettings({ trailFadeRate: v }); },
  onSimSpeedChange: (v) => { sim.simSpeed = v; updateSettings({ simSpeed: v }); },
  onRootChange: (root) => {
    updateSettings({ root });
    const s = getState().settings;
    audio.updateScale(s.root, s.mode, s.octaveMin, s.octaveMax);
  },
  onModeChange: (mode) => {
    updateSettings({ mode });
    const s = getState().settings;
    audio.updateScale(s.root, s.mode, s.octaveMin, s.octaveMax);
  },
  onOctaveMinChange: (oct) => {
    updateSettings({ octaveMin: oct });
    const s = getState().settings;
    audio.updateScale(s.root, s.mode, s.octaveMin, s.octaveMax);
  },
  onOctaveMaxChange: (oct) => {
    updateSettings({ octaveMax: oct });
    const s = getState().settings;
    audio.updateScale(s.root, s.mode, s.octaveMin, s.octaveMax);
  },
  onDefaultSynthChange: (synth) => updateSettings({ defaultSynth: synth }),
  onReverbMixChange: (v) => { audio.setReverbMix(v); updateSettings({ reverbMix: v }); },
  onDelayMixChange: (v) => { audio.setDelayMix(v); updateSettings({ delayMix: v }); },
  onMasterVolumeChange: (v) => { audio.setMasterVolume(v); updateSettings({ masterVolume: v }); },
  onAddTriggerLine: () => {
    addTriggerLine();
    triggerDetector.setLines(getState().triggerLines);
  },
  onResetTriggerLines: () => {
    resetTriggerLines();
    triggerDetector.setLines(getState().triggerLines);
  },
});

const statusBar = new StatusBar(statusBarEl);

const spawnHandler = new SpawnHandler(canvas, {
  onSpawn: (position, velocity, mass) => {
    const body = sim.addPlanet(position, velocity, mass);
    const state = getState();
    addPlanetState({
      id: body.id,
      name: body.name,
      color: body.color,
      muted: false,
      soloed: false,
      synthType: state.settings.defaultSynth,
      volume: 0.75,
      pan: 0,
    });
    audio.addVoice(body.id, state.settings.defaultSynth);
    refreshSidebar();
  },
  getDefaultMass: () => 10,
});

const triggerLineInteraction = new TriggerLineInteraction(canvas, {
  onSelectLine: (id) => selectTriggerLine(id),
  onRotateLine: (id, angle) => {
    updateTriggerLine(id, angle);
    triggerDetector.setLines(getState().triggerLines);
  },
});

new KeyboardHandler({
  onTogglePause: () => { sim.running = !sim.running; },
  onDeleteSelected: () => {
    const id = getSelectedPlanetId();
    if (id) deletePlanet(id);
  },
  onMuteSelected: () => {
    const id = getSelectedPlanetId();
    if (id) {
      const body = sim.bodies.find((b) => b.id === id);
      if (body) {
        body.muted = !body.muted;
        audio.mutePlanet(id, body.muted);
        const state = getState().planets.get(id);
        if (state) updatePlanet(id, { muted: body.muted });
        refreshSidebar();
      }
    }
  },
  onSoloSelected: () => {
    const id = getSelectedPlanetId();
    if (id) {
      const body = sim.bodies.find((b) => b.id === id);
      if (body) {
        body.soloed = !body.soloed;
        const s = getState().planets.get(id);
        if (s) updatePlanet(id, { soloed: body.soloed });
        refreshSidebar();
      }
    }
  },
  onSetSynth: (index) => {
    const id = getSelectedPlanetId();
    if (!id) return;
    const types: SynthType[] = ['sine', 'triangle', 'sawtooth', 'square', 'fm', 'marimba', 'bell', 'pluck'];
    const type = types[index];
    if (!type) return;
    audio.updateSynthType(id, type);
    updatePlanet(id, { synthType: type });
    refreshSidebar();
  },
  onToggleNBody: () => {
    sim.nBodyEnabled = !sim.nBodyEnabled;
    updateSettings({ nBodyEnabled: sim.nBodyEnabled });
    controls.setNBodyEnabled(sim.nBodyEnabled);
  },
  onResetAll: () => {
    sim.reset();
    // Remove all audio voices
    for (const [id] of getState().planets) {
      audio.removeVoice(id);
    }
    resetAll();
    refreshSidebar();
  },
  onTogglePanels: () => {
    sidebarEl.classList.toggle('collapsed');
    controlsEl.classList.toggle('collapsed');
  },
  onShowShortcuts: () => shortcutsOverlay.show(),
});

// === Helpers ===

function deletePlanet(id: string): void {
  sim.removeBody(id);
  audio.removeVoice(id);
  removePlanetState(id);
  if (getSelectedPlanetId() === id) selectPlanet(null);
  refreshSidebar();
}

function refreshSidebar(): void {
  const state = getState();
  sidebar.update(sim.bodies, state.selectedPlanetId);

  // Update editor
  const selectedId = state.selectedPlanetId;
  const body = selectedId ? sim.bodies.find((b) => b.id === selectedId) ?? null : null;
  const planetState = selectedId ? state.planets.get(selectedId) : null;
  sidebar.updateEditor(
    body,
    planetState?.synthType ?? 'fm',
    planetState?.volume ?? 0.75,
    planetState?.pan ?? 0,
    (type) => {
      if (!selectedId) return;
      audio.updateSynthType(selectedId, type);
      updatePlanet(selectedId, { synthType: type });
    },
    (vol) => {
      if (!selectedId) return;
      audio.setPlanetVolume(selectedId, vol);
      updatePlanet(selectedId, { volume: vol });
    },
    (pan) => {
      if (!selectedId) return;
      audio.setPlanetPan(selectedId, pan);
      updatePlanet(selectedId, { pan });
    },
    (mass) => {
      if (!selectedId) return;
      const body = sim.bodies.find((b) => b.id === selectedId);
      if (body) {
        body.mass = mass;
        body.radius = massToRadius(mass);
      }
    },
    (color) => {
      if (!selectedId) return;
      const body = sim.bodies.find((b) => b.id === selectedId);
      if (body) body.color = color;
      updatePlanet(selectedId, { color });
    },
  );
}

// === Canvas click for planet selection ===
canvas.addEventListener('click', (e) => {
  const planet = findPlanetAt(sim.bodies, e.clientX, e.clientY);
  if (planet) {
    selectPlanet(planet.id);
  } else {
    selectPlanet(null);
    selectTriggerLine(null);
  }
  refreshSidebar();
});

// === Resize handling ===
function handleResize(): void {
  renderer.resize();
  sim.updateCanvasSize(window.innerWidth, window.innerHeight);
}

window.addEventListener('resize', handleResize);
handleResize();

// === "Click to Begin" overlay ===
overlay.addEventListener('click', async () => {
  await audio.start();
  overlay.classList.add('hidden');
});

// === Simulation body removal callback ===
sim.onBodyRemoved = (id) => {
  audio.removeVoice(id);
  removePlanetState(id);
  if (getSelectedPlanetId() === id) selectPlanet(null);
  refreshSidebar();
};

// === Main Loop ===
function mainLoop(): void {
  requestAnimationFrame(mainLoop);

  // FPS tracking
  frameCount++;
  const now = performance.now();
  if (now - fpsTime >= 1000) {
    currentFps = frameCount / ((now - fpsTime) / 1000);
    frameCount = 0;
    fpsTime = now;
  }

  // 1. Simulation step
  sim.step();

  // 2. Trigger detection
  const state = getState();
  triggerDetector.setLines(state.triggerLines);
  triggerLineInteraction.update(state.triggerLines, sim.sun.position.x, sim.sun.position.y);

  const events = triggerDetector.detect(sim.planets, sim.sun.position.x, sim.sun.position.y);

  // 3. Audio scheduling
  const visualEvents: VisualEvent[] = [];
  for (const event of events) {
    audio.handleTrigger(event);

    // Create visual event for renderer
    const planet = sim.bodies.find((b) => b.id === event.planetId);
    if (planet) {
      // Compute crossing position
      const crossX = sim.sun.position.x + Math.cos(event.angle) * event.distance;
      const crossY = sim.sun.position.y + Math.sin(event.angle) * event.distance;
      visualEvents.push({
        type: 'trigger',
        x: crossX,
        y: crossY,
        planetColor: planet.color,
        planetRadius: planet.radius,
      });
    }
  }

  // 4. Render
  renderer.render(
    sim.bodies,
    state.triggerLines,
    state.selectedPlanetId,
    state.selectedTriggerLineId,
    spawnHandler.state,
    visualEvents,
    1 / 60,
  );

  // 5. Status bar update
  statusBar.update(
    sim.planets.length,
    currentFps,
    state.settings.root,
    state.settings.mode,
    audio.getTriggersPerMinute(),
  );
}

// Start the loop
requestAnimationFrame(mainLoop);

/**
