/**
 * Tests for gravitational force computation.
 * Validates the core physics: force law, softening, Newton's 3rd law.
 */

import { describe, it, expect } from 'vitest';
import { gravitationalForce, computeForces } from '../forces.js';
import type { Body } from '../../simulation/types.js';
import { vec2 } from '../../../lib/math.js';

function makeBody(id: string, x: number, y: number, mass: number): Body {
  return {
    id,
    mass,
    position: vec2(x, y),
    velocity: vec2(0, 0),
    acceleration: vec2(0, 0),
    prevPosition: vec2(x, y),
    radius: 5,
    isAnchor: false,
    color: '#fff',
    escapedAt: 0,
    name: id,
    muted: false,
    soloed: false,
  };
}

describe('gravitationalForce', () => {
  it('computes force between two bodies', () => {
    const a = makeBody('a', 0, 0, 100);
    const b = makeBody('b', 100, 0, 100);
    const { fx, fy } = gravitationalForce(a, b, 1.0, 5.0);

    // F = G * m1 * m2 / (r² + ε²) = 1 * 100 * 100 / (10000 + 25)
    const expectedMag = (1 * 100 * 100) / (10000 + 25);
    expect(fx).toBeCloseTo(expectedMag);
    expect(fy).toBeCloseTo(0);
  });

  it('applies softening to prevent singularities', () => {
    const a = makeBody('a', 0, 0, 100);
    const b = makeBody('b', 0.1, 0, 100);
    const { fx, fy } = gravitationalForce(a, b, 1.0, 5.0);

    // Without softening, r² = 0.01 → F would be huge
    // With ε=5: F = 1 * 100 * 100 / (0.01 + 25) ≈ 399.84
    const expectedMag = (10000) / (0.01 + 25);
    expect(fx).toBeCloseTo(expectedMag);
    expect(Math.abs(fy)).toBeLessThan(0.001);
  });

  it('force is symmetrical (Newton\'s 3rd law)', () => {
    const a = makeBody('a', 0, 0, 100);
    const b = makeBody('b', 50, 50, 200);
    const fab = gravitationalForce(a, b, 1.0, 5.0);
    const fba = gravitationalForce(b, a, 1.0, 5.0);

    expect(fab.fx).toBeCloseTo(-fba.fx);
    expect(fab.fy).toBeCloseTo(-fba.fy);
  });
});

describe('computeForces', () => {
  it('resets accelerations before computing', () => {
    const sun: Body = {
      id: 'sun', mass: 10000, position: vec2(500, 500),
      velocity: vec2(0, 0), acceleration: vec2(99, 99),
      prevPosition: vec2(500, 500), radius: 25,
      isAnchor: true, color: '#ffd54f', escapedAt: 0,
      name: 'Sun', muted: false, soloed: false,
    };
    const planet = makeBody('p1', 600, 500, 10);
    planet.acceleration = vec2(99, 99);

    computeForces([sun, planet], sun, 1.0, 5.0, false);

    // Sun acceleration should be reset (sun is immovable)
    expect(sun.acceleration.x).toBe(0);
    expect(sun.acceleration.y).toBe(0);

    // Planet should have non-zero acceleration toward sun
    expect(planet.acceleration.x).toBeLessThan(0);
  });

  it('with N-body disabled, only computes sun-planet forces', () => {
    const sun: Body = {
      id: 'sun', mass: 10000, position: vec2(500, 500),
      velocity: vec2(0, 0), acceleration: vec2(0, 0),
      prevPosition: vec2(500, 500), radius: 25,
      isAnchor: true, color: '#ffd54f', escapedAt: 0,
      name: 'Sun', muted: false, soloed: false,
    };
    const p1 = makeBody('p1', 600, 500, 10);
    const p2 = makeBody('p2', 400, 500, 10);

    computeForces([sun, p1, p2], sun, 1.0, 5.0, false);

    // Each planet should be attracted toward sun
    expect(p1.acceleration.x).toBeLessThan(0); // sun is to the left
    expect(p2.acceleration.x).toBeGreaterThan(0); // sun is to the right
  });

  it('with N-body enabled, planets also interact with each other', () => {
    const sun: Body = {
      id: 'sun', mass: 10000, position: vec2(500, 500),
      velocity: vec2(0, 0), acceleration: vec2(0, 0),
      prevPosition: vec2(500, 500), radius: 25,
      isAnchor: true, color: '#ffd54f', escapedAt: 0,
      name: 'Sun', muted: false, soloed: false,
    };
    const p1 = makeBody('p1', 550, 500, 1000); // heavy planet
    const p2 = makeBody('p2', 560, 500, 1000); // close to p1

    // Without N-body
    computeForces([sun, p1, p2], sun, 1.0, 5.0, false);
    const acc1_noNBody = { x: p1.acceleration.x, y: p1.acceleration.y };

    // With N-body
    p1.acceleration = vec2(0, 0);
    p2.acceleration = vec2(0, 0);
    computeForces([sun, p1, p2], sun, 1.0, 5.0, true);

    // With N-body, p1 should have extra acceleration from p2
    // (p2 is to the right of p1, so p1 should be pulled more to the right)
    expect(p1.acceleration.x).toBeGreaterThan(acc1_noNBody.x);
  });
});

/**
 * Tests for Velocity Verlet integration.
 * Validates energy conservation and correct position/velocity updates.
 */

import { describe, it, expect } from 'vitest';
import { positionUpdate, velocityUpdate, saveAccelerations } from '../integrator.js';
import type { Body } from '../types.js';
import { vec2 } from '../../lib/math.js';

function makePlanet(x: number, y: number, vx: number, vy: number, mass: number): Body {
  return {
    id: 'test',
    mass,
    position: vec2(x, y),
    velocity: vec2(vx, vy),
    acceleration: vec2(0, 0),
    prevPosition: vec2(x, y),
    radius: 5,
    isAnchor: false,
    color: '#fff',
    escapedAt: 0,
    name: 'Test',
    muted: false,
    soloed: false,
  };
}

describe('positionUpdate', () => {
  it('updates position using current velocity and acceleration', () => {
    const body = makePlanet(0, 0, 10, 0, 1);
    body.acceleration = vec2(5, 0);

    positionUpdate([body], 1);

    // x = 0 + 10*1 + 0.5*5*1² = 12.5
    expect(body.position.x).toBeCloseTo(12.5);
    expect(body.position.y).toBeCloseTo(0);
  });

  it('stores prevPosition before update', () => {
    const body = makePlanet(5, 10, 0, 0, 1);
    positionUpdate([body], 1);

    expect(body.prevPosition.x).toBe(5);
    expect(body.prevPosition.y).toBe(10);
  });

  it('does not move anchor bodies', () => {
    const sun: Body = {
      id: 'sun', mass: 10000,
      position: vec2(500, 500),
      velocity: vec2(0, 0),
      acceleration: vec2(10, 10),
      prevPosition: vec2(500, 500),
      radius: 25, isAnchor: true, color: '#ffd54f',
      escapedAt: 0, name: 'Sun', muted: false, soloed: false,
    };

    positionUpdate([sun], 1);

    expect(sun.position.x).toBe(500);
    expect(sun.position.y).toBe(500);
  });
});

describe('velocityUpdate', () => {
  it('updates velocity using average of old and new acceleration', () => {
    const body = makePlanet(0, 0, 0, 0, 1);
    const oldAcc = [{ x: 2, y: 0 }];
    body.acceleration = vec2(4, 0);

    velocityUpdate([body], oldAcc, 1);

    // v = 0 + 0.5 * (2 + 4) * 1 = 3
    expect(body.velocity.x).toBeCloseTo(3);
    expect(body.velocity.y).toBeCloseTo(0);
  });
});

describe('saveAccelerations', () => {
  it('saves current accelerations', () => {
    const body = makePlanet(0, 0, 0, 0, 1);
    body.acceleration = vec2(5, 10);

    const saved = saveAccelerations([body]);

    expect(saved[0]).toEqual({ x: 5, y: 10 });
  });
});

describe('Velocity Verlet integration (full step)', () => {
  it('conserves energy in a circular orbit (approximately)', () => {
    // Set up a circular orbit around the origin
    // For a circular orbit: v = sqrt(GM/r), with G=1, M=10000, r=200
    // v = sqrt(10000/200) = sqrt(50) ≈ 7.07
    const r = 200;
    const v = Math.sqrt(10000 / r);

    const body = makePlanet(r, 0, 0, v, 1);

    // Initial energy
    const initialKE = 0.5 * body.mass * (body.velocity.x ** 2 + body.velocity.y ** 2);
    const initialPE = -10000 * body.mass / r;
    const initialE = initialKE + initialPE;

    // Simulate for 100 steps
    const dt = 1 / 60;
    const sun: Body = {
      id: 'sun', mass: 10000, position: vec2(0, 0),
      velocity: vec2(0, 0), acceleration: vec2(0, 0),
      prevPosition: vec2(0, 0), radius: 25,
      isAnchor: true, color: '#ffd54f', escapedAt: 0,
      name: 'Sun', muted: false, soloed: false,
    };

    for (let step = 0; step < 100; step++) {
      // Compute forces
      const dx = sun.position.x - body.position.x;
      const dy = sun.position.y - body.position.y;
      const distSq = dx * dx + dy * dy + 25; // softening
      const dist = Math.sqrt(distSq);
      const forceMag = (1 * body.mass * sun.mass) / distSq;
      body.acceleration.x = forceMag * (dx / dist) / body.mass;
      body.acceleration.y = forceMag * (dy / dist) / body.mass;

      // Save old acceleration
      const oldAcc = saveAccelerations([body]);

      // Position update
      positionUpdate([body], dt);

      // Recompute forces at new position
      const dx2 = sun.position.x - body.position.x;
      const dy2 = sun.position.y - body.position.y;
      const distSq2 = dx2 * dx2 + dy2 * dy2 + 25;
      const dist2 = Math.sqrt(distSq2);
      const forceMag2 = (1 * body.mass * sun.mass) / distSq2;
      body.acceleration.x = forceMag2 * (dx2 / dist2) / body.mass;
      body.acceleration.y = forceMag2 * (dy2 / dist2) / body.mass;

      // Velocity update
      velocityUpdate([body], oldAcc, dt);
    }

    // Check energy conservation (should be within 5% due to softening and finite dt)
    const finalKE = 0.5 * body.mass * (body.velocity.x ** 2 + body.velocity.y ** 2);
    const finalDist = Math.sqrt(
      (body.position.x - sun.position.x) ** 2 +
      (body.position.y - sun.position.y) ** 2,
    );
    const finalPE = -10000 * body.mass / finalDist;
    const finalE = finalKE + finalPE;

    // Energy should be approximately conserved (within 10% for this simplified test)
    expect(Math.abs((finalE - initialE) / initialE)).toBeLessThan(0.1);
  });
});

/**
 * Tests for the main Simulation class.
 * Validates body management, escape detection, and sun immobility.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Simulation } from '../simulation.js';
import { vec2 } from '../../lib/math.js';

describe('Simulation', () => {
  let sim: Simulation;

  beforeEach(() => {
    sim = new Simulation(1000, 800);
  });

  describe('initialization', () => {
    it('has a sun at canvas center', () => {
      expect(sim.sun.position.x).toBe(500);
      expect(sim.sun.position.y).toBe(400);
      expect(sim.sun.isAnchor).toBe(true);
    });

    it('starts with running = true', () => {
      expect(sim.running).toBe(true);
    });

    it('has default G = 1.0', () => {
      expect(sim.G).toBe(1.0);
    });
  });

  describe('addPlanet', () => {
    it('adds a planet to the bodies list', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      expect(sim.planets.length).toBe(1);
      expect(sim.planets[0].id).toBe(planet.id);
    });

    it('calls onBodyAdded callback', () => {
      let addedId: string | null = null;
      sim.onBodyAdded = (body) => { addedId = body.id; };

      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      expect(addedId).toBe(planet.id);
    });

    it('derives radius from mass', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 27);
      // radius = clamp(27^(1/3) * 2, 4, 20) = clamp(6, 4, 20) = 6
      expect(planet.radius).toBeCloseTo(Math.pow(27, 1 / 3) * 2);
    });

    it('clamps radius to minimum 4px', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 0.5);
      expect(planet.radius).toBe(4);
    });

    it('clamps radius to maximum 20px', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 5000);
      expect(planet.radius).toBe(20);
    });

    it('assigns a unique ID', () => {
      const p1 = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      const p2 = sim.addPlanet(vec2(400, 400), vec2(0, -3), 10);
      expect(p1.id).not.toBe(p2.id);
    });

    it('assigns a non-anchor planet', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      expect(planet.isAnchor).toBe(false);
    });
  });

  describe('removeBody', () => {
    it('removes a planet by ID', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      sim.removeBody(planet.id);
      expect(sim.planets.length).toBe(0);
    });

    it('calls onBodyRemoved callback', () => {
      let removedId: string | null = null;
      sim.onBodyRemoved = (id) => { removedId = id; };

      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      sim.removeBody(planet.id);
      expect(removedId).toBe(planet.id);
    });

    it('cannot remove the sun', () => {
      sim.removeBody('sun');
      expect(sim.bodies).toContain(sim.sun);
    });
  });

  describe('reset', () => {
    it('removes all planets but keeps the sun', () => {
      sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      sim.addPlanet(vec2(400, 400), vec2(0, -3), 10);
      sim.reset();
      expect(sim.planets.length).toBe(0);
      expect(sim.bodies).toContain(sim.sun);
    });

    it('calls onBodyRemoved for each planet', () => {
      const removed: string[] = [];
      sim.onBodyRemoved = (id) => removed.push(id);

      const p1 = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      const p2 = sim.addPlanet(vec2(400, 400), vec2(0, -3), 10);
      sim.reset();
      expect(removed).toContain(p1.id);
      expect(removed).toContain(p2.id);
    });
  });

  describe('step', () => {
    it('does not step when paused', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      const initialPos = { ...planet.position };
      sim.running = false;
      sim.step();
      expect(planet.position.x).toBe(initialPos.x);
      expect(planet.position.y).toBe(initialPos.y);
    });

    it('updates positions when running', () => {
      const planet = sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      const initialPos = { ...planet.position };
      sim.step();
      // Position should have changed (at least velocity contribution)
      expect(planet.position.y).not.toBe(initialPos.y);
    });

    it('sun stays immovable after steps', () => {
      sim.addPlanet(vec2(600, 400), vec2(0, 3), 10);
      const sunPos = { ...sim.sun.position };
      sim.step();
      expect(sim.sun.position.x).toBe(sunPos.x);
      expect(sim.sun.position.y).toBe(sunPos.y);
    });
  });

  describe('escape detection', () => {
    it('flags planets beyond 2× canvas diagonal', () => {
      const planet = sim.addPlanet(vec2(10000, 10000), vec2(0, 0), 10);
      sim.step();
      expect(planet.escapedAt).toBeGreaterThan(0);
    });
  });

  describe('updateCanvasSize', () => {
    it('moves sun to new center', () => {
      sim.updateCanvasSize(1200, 600);
      expect(sim.sun.position.x).toBe(600);
      expect(sim.sun.position.y).toBe(300);
    });
  });
});

/**
 * Tests for musical scale definitions and note array generation.
 * These ensure correct scale intervals, root transposition, and octave stacking.
 */

import { describe, it, expect } from 'vitest';
import { SCALES, noteToMidi, generateNoteArray, midiToFrequency } from '../scales.js';

describe('SCALES', () => {
  it('has 7 modes defined', () => {
    expect(Object.keys(SCALES).length).toBe(7);
  });

  it('each mode has 7 intervals starting at 0', () => {
    for (const [mode, intervals] of Object.entries(SCALES)) {
      expect(intervals.length, `Mode ${mode} should have 7 intervals`).toBe(7);
      expect(intervals[0], `${mode} should start at 0`).toBe(0);
    }
  });

  it('Lydian mode has the sharp 4th (interval 6)', () => {
    expect(SCALES.lydian).toEqual([0, 2, 4, 6, 7, 9, 11]);
  });

  it('Ionian (major) has standard intervals', () => {
    expect(SCALES.ionian).toEqual([0, 2, 4, 5, 7, 9, 11]);
  });
});

describe('noteToMidi', () => {
  it('maps C to 0', () => {
    expect(noteToMidi('C')).toBe(0);
  });

  it('maps A to 9', () => {
    expect(noteToMidi('A')).toBe(9);
  });

  it('maps C# to 1', () => {
    expect(noteToMidi('C#')).toBe(1);
  });

  it('maps Db to 1 (enharmonic equivalent)', () => {
    expect(noteToMidi('Db')).toBe(1);
  });

  it('maps B to 11', () => {
    expect(noteToMidi('B')).toBe(11);
  });
});

describe('generateNoteArray', () => {
  it('generates notes for C Lydian octave 4 only', () => {
    const notes = generateNoteArray('C', 'lydian', 4, 4);
    // C Lydian: C D E F# G A B = 0 2 4 6 7 9 11 + octave*12
    // Octave 4: 48 50 52 54 55 57 59
    expect(notes).toEqual([48, 50, 52, 54, 55, 57, 59]);
  });

  it('generates notes across multiple octaves', () => {
    const notes = generateNoteArray('C', 'lydian', 2, 3);
    expect(notes.length).toBe(14); // 7 notes × 2 octaves
    expect(notes[0]).toBe(24 + 0); // C2 = 24
    expect(notes[notes.length - 1]).toBe(59); // B3 = 59
  });

  it('notes are sorted ascending', () => {
    const notes = generateNoteArray('F#', 'phrygian', 2, 5);
    for (let i = 1; i < notes.length; i++) {
      expect(notes[i]).toBeGreaterThan(notes[i - 1]);
    }
  });

  it('generates correct C Lydian from octave 3 to 5', () => {
    const notes = generateNoteArray('C', 'lydian', 3, 5);
    // 7 notes × 3 octaves = 21 notes
    expect(notes.length).toBe(21);
    // First note: C3 = 36
    expect(notes[0]).toBe(36);
    // Last note: B5 = 83
    expect(notes[notes.length - 1]).toBe(83);
  });
});

describe('midiToFrequency', () => {
  it('A4 (MIDI 69) = 440 Hz', () => {
    expect(midiToFrequency(69)).toBeCloseTo(440);
  });

  it('C4 (MIDI 60) ≈ 261.63 Hz', () => {
    expect(midiToFrequency(60)).toBeCloseTo(261.63, 1);
  });

  it('each octave doubles frequency', () => {
    const f1 = midiToFrequency(60); // C4
    const f2 = midiToFrequency(72); // C5
    expect(f2 / f1).toBeCloseTo(2);
  });
});

/**
 * Tests for the distance → pitch quantizer.
 * Validates mapping, reversal (close=high), and edge cases.
 */

import { describe, it, expect } from 'vitest';
import { distanceToNote } from '../quantizer.js';

const C_LYDIAN_OCT3_5 = [
  36, 38, 40, 42, 43, 45, 47,  // octave 3
  48, 50, 52, 54, 55, 57, 59,  // octave 4
  60, 62, 64, 66, 67, 69, 71,  // octave 5
];

describe('distanceToNote', () => {
  it('maps close distances to high notes', () => {
    const note = distanceToNote(50, C_LYDIAN_OCT3_5); // minDistance
    // Normalized = 0, reversed = 1 → highest index → 71 (B5)
    expect(note).toBe(71);
  });

  it('maps far distances to low notes', () => {
    const note = distanceToNote(400, C_LYDIAN_OCT3_5); // maxDistance
    // Normalized = 1, reversed = 0 → lowest index → 36 (C3)
    expect(note).toBe(36);
  });

  it('maps mid-range to middle notes', () => {
    const note = distanceToNote(225, C_LYDIAN_OCT3_5); // midpoint
    // Normalized ≈ 0.5, reversed ≈ 0.5 → middle of array
    expect(note).toBeGreaterThan(36);
    expect(note).toBeLessThan(71);
  });

  it('clamps distances below minimum', () => {
    const note = distanceToNote(10, C_LYDIAN_OCT3_5);
    expect(note).toBe(71); // same as minDistance
  });

  it('clamps distances above maximum', () => {
    const note = distanceToNote(500, C_LYDIAN_OCT3_5);
    expect(note).toBe(36); // same as maxDistance
  });

  it('always returns a note from the scale', () => {
    for (let d = 40; d <= 420; d += 10) {
      const note = distanceToNote(d, C_LYDIAN_OCT3_5);
      expect(C_LYDIAN_OCT3_5).toContain(note);
    }
  });

  it('returns middle C fallback for empty scale', () => {
    const note = distanceToNote(200, []);
    expect(note).toBe(60);
  });

  it('uses custom min/max distance', () => {
    const notes = [60, 64, 67, 72];
    const note = distanceToNote(100, notes, 100, 200);
    // At min distance → highest note
    expect(note).toBe(72);
  });
});

/**
 * Tests for trigger line axis-crossing detection.
 * Validates crossing detection, debounce, and configurable lines.
 */

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { TriggerDetector } from '../triggers.js';
import type { Body } from '../../simulation/types.js';
import type { TriggerLineState } from '../../state/types.js';
import { vec2 } from '../../lib/math.js';

function makePlanet(id: string, prevX: number, prevY: number, currX: number, currY: number): Body {
  return {
    id,
    mass: 10,
    position: vec2(currX, currY),
    velocity: vec2(1, 0),
    acceleration: vec2(0, 0),
    prevPosition: vec2(prevX, prevY),
    radius: 5,
    isAnchor: false,
    color: '#fff',
    escapedAt: 0,
    name: id,
    muted: false,
    soloed: false,
  };
}

describe('TriggerDetector', () => {
  let detector: TriggerDetector;

  beforeEach(() => {
    vi.useFakeTimers();
    vi.setSystemTime(0);
    detector = new TriggerDetector([
      { id: 'line-0', angle: 0 },           // X axis (horizontal)
      { id: 'line-1', angle: Math.PI / 2 },  // Y axis (vertical)
    ]);
  });

  describe('X-axis crossing (angle=0)', () => {
    it('detects crossing from top to bottom', () => {
      // Planet moves from y=-1 to y=1, crossing the X axis (y=0)
      const planet = makePlanet('p1', 500, -10, 500, 10);
      const events = detector.detect([planet], 500, 0);

      expect(events.length).toBe(1);
      expect(events[0].planetId).toBe('p1');
      expect(events[0].axis).toBe(0); // line-0
    });

    it('detects crossing from bottom to top', () => {
      const planet = makePlanet('p1', 500, 10, 500, -10);
      const events = detector.detect([planet], 500, 0);

      expect(events.length).toBe(1);
      expect(events[0].crossingDirection).toBe(-1);
    });

    it('does not trigger when staying on same side', () => {
      const planet = makePlanet('p1', 500, 10, 500, 20);
      const events = detector.detect([planet], 500, 0);

      expect(events.length).toBe(0);
    });
  });

  describe('Y-axis crossing (angle=π/2)', () => {
    it('detects crossing from left to right', () => {
      // Planet moves from x=-10 to x=10, crossing the Y axis (x=0 relative to sun)
      const planet = makePlanet('p1', 490, 500, 510, 500);
      const events = detector.detect([planet], 500, 500);

      expect(events.length).toBe(1);
      expect(events[0].axis).toBe(1); // line-1
    });
  });

  describe('debounce', () => {
    it('does not trigger twice within 100ms on the same line', () => {
      // First crossing
      const planet1 = makePlanet('p1', 500, -10, 500, 10);
      const events1 = detector.detect([planet1], 500, 0);
      expect(events1.length).toBe(1);

      // Advance time by 50ms (within debounce period)
      vi.setSystemTime(50);

      // Same planet crosses back
      const planet2 = makePlanet('p1', 500, 10, 500, -10);
      const events2 = detector.detect([planet2], 500, 0);
      expect(events2.length).toBe(0);
    });

    it('triggers again after debounce period', () => {
      // First crossing
      const planet1 = makePlanet('p1', 500, -10, 500, 10);
      detector.detect([planet1], 500, 0);

      // Advance past debounce
      vi.setSystemTime(150);

      // Same planet crosses back
      const planet2 = makePlanet('p1', 500, 10, 500, -10);
      const events2 = detector.detect([planet2], 500, 0);
      expect(events2.length).toBe(1);
    });
  });

  describe('multiple lines', () => {
    it('can detect crossing on different lines simultaneously', () => {
      // Planet at exact diagonal crosses both X and Y axes
      const planet = makePlanet('p1', 490, -10, 510, 10);
      const events = detector.detect([planet], 500, 0);

      // Should detect crossing on line-0 (X axis) and possibly line-1 (Y axis)
      expect(events.length).toBeGreaterThanOrEqual(1);
    });
  });

  describe('configurable lines', () => {
    it('works with custom angle lines', () => {
      detector.setLines([
        { id: 'line-custom', angle: Math.PI / 4 }, // 45 degrees
      ]);

      // Planet crosses a 45-degree line through origin
      // Normal to 45° line is (sin(45°), -cos(45°)) ≈ (0.707, -0.707)
      // For crossing: move from one side to the other
      const planet = makePlanet('p1', 0, 10, 10, 0); // moving toward and across the line
      const events = detector.detect([planet], 0, 0);

      // This should detect a crossing if prev and curr are on opposite sides
      // prevSigned = 0*0.707 + 10*(-0.707) = -7.07
      // currSigned = 10*0.707 + 0*(-0.707) = 7.07
      // Signs differ → crossing detected
      expect(events.length).toBe(1);
    });
  });
});

