/**
 * Visual effects — trigger ripples, sun flash, selection ring.
 */

import type { Ripple } from './types.js';
import { hexToRgba } from '../lib/colors.js';

export class Effects {
  private ripples: Ripple[] = [];
  private sunFlashTime = 0;
  private sunFlashDuration = 200;

  /** Create a ripple at a trigger crossing point */
  addRipple(x: number, y: number, planetRadius: number, planetColor: string): void {
    this.ripples.push({
      x,
      y,
      radius: planetRadius,
      maxRadius: 40,
      life: 400,
      maxLife: 400,
      color: planetColor,
      lineWidth: 2,
      active: true,
    });
    this.sunFlashTime = this.sunFlashDuration;
  }

  /** Trigger sun flash */
  flashSun(): void {
    this.sunFlashTime = this.sunFlashDuration;
  }

  /** Update all active effects */
  update(dtMs: number): void {
    // Update ripples
    for (const r of this.ripples) {
      if (!r.active) continue;
      r.life -= dtMs;
      if (r.life <= 0) {
        r.active = false;
        continue;
      }
      const progress = 1 - r.life / r.maxLife;
      r.radius = r.x !== undefined ? r.radius : 0; // keep reference
      // Interpolate radius from start to max
      const startRadius = r.maxRadius * (1 - (r.maxLife / r.maxLife)); // always 0 logic; let's fix
    }

    // Actually update ripple radii properly
    for (const r of this.ripples) {
      if (!r.active) continue;
      const progress = 1 - r.life / r.maxLife;
      // Overwrite the radius to interpolate
      (r as { _currentRadius: number })._currentRadius =
        (1 - progress) * 0 + progress * r.maxRadius; // from 0 to maxRadius
